1	/**
2	 * Audit Trail Page (/audit)
3	 * Data Source: fact_outcomes full join with dimensions
4	 * Human-readable log, CSV export button, date range filter.
5	 */
6	import React, { useEffect, useState } from 'react';
7	import { useNavigate } from 'react-router-dom';
8	import { supabase } from '../supabaseClient';
9	import { AGENT_API_KEY_STORAGE_KEY } from '../hooks/useAgentApiKey';
10	
11	interface AuditRow {
12	    outcome_id: string;
13	    agent_name: string;
14	    action_name: string;
15	    issue_type: string;
16	    success: boolean;
17	    timestamp: string;
18	    response_time_ms: number | null;
19	    error_code: string | null;
20	    error_message: string | null;
21	    session_id: string;
22	}
23	
24	export default function AuditTrail() {
25	    const navigate = useNavigate();
26	    const [rows, setRows] = useState<AuditRow[]>([]);
27	    const [loading, setLoading] = useState(true);
28	    const [error, setError] = useState<string | null>(null);
29	    const [startDate, setStartDate] = useState('');
30	    const [endDate, setEndDate] = useState('');
31	
32	    let hasStoredApiKey = false;
33	    try {
34	        hasStoredApiKey = Boolean(localStorage.getItem(AGENT_API_KEY_STORAGE_KEY));
35	    } catch {
36	        hasStoredApiKey = false;
37	    }
38	
39	    useEffect(() => { fetchAudit(); }, [startDate, endDate]);
40	
41	    async function fetchAudit() {
42	        setLoading(true);
43	        setError(null);
44	
45	        try {
46	            let query = supabase
47	                .from('fact_outcomes')
48	                .select(`
49	                    outcome_id, success, timestamp, response_time_ms, error_code, error_message, session_id,
50	                    dim_actions!inner(action_name),
51	                    dim_agents!inner(agent_name),
52	                    dim_contexts!inner(issue_type)
53	                `)
54	                .eq('is_deleted', false)
55	                .order('timestamp', { ascending: false })
56	                .limit(100);
57	
58	            if (startDate) query = query.gte('timestamp', startDate);
59	            if (endDate) query = query.lte('timestamp', endDate + 'T23:59:59Z');
60	
61	            const { data, error: queryError } = await query;
62	
63	            if (queryError) {
64	                throw new Error(queryError.message);
65	            }
66	
67	            setRows(data.map((r: any) => ({
68	                outcome_id: r.outcome_id,
69	                agent_name: r.dim_agents?.agent_name ?? '',
70	                action_name: r.dim_actions?.action_name ?? '',
71	                issue_type: r.dim_contexts?.issue_type ?? '',
72	                success: r.success,
73	                timestamp: r.timestamp,
74	                response_time_ms: r.response_time_ms,
75	                error_code: r.error_code,
76	                error_message: r.error_message,
77	                session_id: r.session_id,
78	            })));
79	        } catch (err) {
80	            setRows([]);
81	            setError(err instanceof Error ? err.message : 'Failed to load audit trail');
82	        } finally {
83	            setLoading(false);
84	        }
85	    }
86	
87	    function exportCSV() {
88	        const header = 'outcome_id,timestamp,agent,action,issue_type,success,response_ms,error_code,error_message,session_id\n';
89	        const csv = rows.map(r =>
90	            `${r.outcome_id},${r.timestamp},${r.agent_name},${r.action_name},${r.issue_type},${r.success},${r.response_time_ms ?? ''},${r.error_code ?? ''},${(r.error_message ?? '').replace(/,/g, ';')},${r.session_id}`
91	        ).join('\n');
92	
93	        const blob = new Blob([header + csv], { type: 'text/csv' });
94	        const url = URL.createObjectURL(blob);
95	        const a = document.createElement('a');
96	        a.href = url;
97	        a.download = `layerinfinite-audit-${new Date().toISOString().slice(0, 10)}.csv`;
98	        a.click();
99	        URL.revokeObjectURL(url);
100	    }
101	
102	    return (
103	        <div>
104	            <style>{`@keyframes audit-spin { to { transform: rotate(360deg); } }`}</style>
105	            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem', flexWrap: 'wrap', gap: '0.75rem' }}>
106	                <h1 style={{ fontSize: '1.5rem', fontWeight: 700, color: '#1e293b', margin: 0 }}>
107	                    Audit Trail
108	                </h1>
109	                <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
110	                    <label style={{ fontSize: '0.8rem', color: '#64748b' }}>
111	                        From: <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} style={dateInput} />
112	                    </label>
113	                    <label style={{ fontSize: '0.8rem', color: '#64748b' }}>
114	                        To: <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} style={dateInput} />
115	                    </label>
116	                    <button onClick={exportCSV} style={{
117	                        padding: '0.4rem 1rem', borderRadius: '6px', border: '1px solid #3b82f6',
118	                        background: '#3b82f6', color: '#fff', cursor: 'pointer', fontSize: '0.85rem', fontWeight: 500,
119	                    }}>
120	                        Export CSV
121	                    </button>
122	                </div>
123	            </div>
124	
125	            {!hasStoredApiKey && (
126	                <div style={{
127	                    marginBottom: '1rem',
128	                    color: '#854d0e',
129	                    background: 'rgba(245,158,11,0.12)',
130	                    border: '1px solid rgba(245,158,11,0.3)',
131	                    borderRadius: '10px',
132	                    padding: '0.9rem 1rem',
133	                    display: 'flex',
134	                    justifyContent: 'space-between',
135	                    alignItems: 'center',
136	                    gap: '1rem',
137	                    flexWrap: 'wrap',
138	                }}>
139	                    <span>To view your audit trail, go to Settings {'->'} API Keys and create an API key first. Your key is used to authenticate the audit export.</span>
140	                    <button
141	                        onClick={() => navigate('/dashboard/settings/api-keys')}
142	                        style={{
143	                            padding: '0.35rem 0.8rem',
144	                            borderRadius: '6px',
145	                            border: '1px solid #b45309',
146	                            background: '#f59e0b',
147	                            color: '#111827',
148	                            cursor: 'pointer',
149	                            fontSize: '0.8rem',
150	                            fontWeight: 600,
151	                        }}
152	                    >
153	                        Go to API Keys
154	                    </button>
155	                </div>
156	            )}
157	
158	            {loading ? (
159	                <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
160	                    <div style={{ width: 22, height: 22, borderRadius: '50%', border: '2px solid #334155', borderTopColor: '#94a3b8', animation: 'audit-spin 0.8s linear infinite' }} />
161	                </div>
162	            ) : error ? (
163	                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: '1rem', color: '#f87171', background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.25)', borderRadius: '10px', padding: '0.9rem 1rem' }}>
164	                    <span>{error}</span>
165	                    <button onClick={fetchAudit} style={{ padding: '0.35rem 0.8rem', borderRadius: '6px', border: '1px solid #334155', background: '#0f172a', color: '#fff', cursor: 'pointer', fontSize: '0.8rem' }}>Retry</button>
166	                </div>
167	            ) : rows.length === 0 ? (
168	                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center', padding: '5rem 1rem' }}>
169	                    <div style={{ fontSize: '2.5rem', opacity: 0.2, marginBottom: '0.75rem' }}>📋</div>
170	                    <h3 style={{ color: '#0f172a', margin: 0, fontSize: '1.1rem' }}>No outcomes logged yet</h3>
171	                    <p style={{ color: '#64748b', marginTop: '0.6rem', maxWidth: 380, lineHeight: 1.5 }}>
172	                        Every decision your agent makes is recorded here. Start logging outcomes to build your audit trail.
173	                    </p>
174	                </div>
175	            ) : (
176	                <div style={{ overflowX: 'auto' }}>
177	                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.82rem' }}>
178	                        <thead>
179	                            <tr style={{ background: '#f8fafc', borderBottom: '2px solid #e2e8f0' }}>
180	                                <th style={th}>Time</th>
181	                                <th style={th}>Agent</th>
182	                                <th style={th}>Action</th>
183	                                <th style={th}>Context</th>
184	                                <th style={th}>Result</th>
185	                                <th style={th}>Response</th>
186	                                <th style={th}>Error</th>
187	                                <th style={th}>Session</th>
188	                            </tr>
189	                        </thead>
190	                        <tbody>
191	                            {rows.map(r => (
192	                                <tr key={r.outcome_id} style={{ borderBottom: '1px solid #f1f5f9' }}>
193	                                    <td style={td}>{new Date(r.timestamp).toLocaleString()}</td>
194	                                    <td style={td}>{r.agent_name}</td>
195	                                    <td style={td}><code style={{ fontSize: '0.78rem' }}>{r.action_name}</code></td>
196	                                    <td style={td}>{r.issue_type}</td>
197	                                    <td style={td}>
198	                                        <span style={{
199	                                            padding: '1px 6px', borderRadius: '9999px', fontSize: '0.72rem', fontWeight: 600,
200	                                            background: r.success ? '#f0fdf4' : '#fef2f2',
201	                                            color: r.success ? '#16a34a' : '#dc2626',
202	                                        }}>{r.success ? 'OK' : 'FAIL'}</span>
203	                                    </td>
204	                                    <td style={td}>{r.response_time_ms ? `${r.response_time_ms}ms` : '—'}</td>
205	                                    <td style={{ ...td, color: '#94a3b8', maxWidth: '200px', overflow: 'hidden', textOverflow: 'ellipsis' }}>
206	                                        {r.error_message ?? r.error_code ?? '—'}
207	                                    </td>
208	                                    <td style={{ ...td, fontFamily: 'monospace', fontSize: '0.72rem', color: '#94a3b8' }}>
209	                                        {r.session_id.slice(0, 8)}
210	                                    </td>
211	                                </tr>
212	                            ))}
213	                        </tbody>
214	                    </table>
215	                </div>
216	            )}
217	        </div>
218	    );
219	}
220	
221	const th: React.CSSProperties = { textAlign: 'left', padding: '0.5rem 0.6rem', color: '#475569', fontWeight: 600 };
222	const td: React.CSSProperties = { padding: '0.4rem 0.6rem', color: '#1e293b', whiteSpace: 'nowrap' };
223	const dateInput: React.CSSProperties = { padding: '0.3rem 0.5rem', borderRadius: '4px', border: '1px solid #cbd5e1', fontSize: '0.8rem', marginLeft: '0.25rem' };
