1	/**
2	 * Alerts Page (/alerts)
3	 * Data Source: degradation_alert_events (migrations 008 + 017)
4	 * Gap detection dashboard — surfaces all anomalies Layerinfinite detects.
5	 */
6	import React, { useEffect, useState, useCallback, useRef } from 'react';
7	import { supabase } from '../supabaseClient';
8	import AlertTypeSummary from '../components/AlertTypeSummary';
9	import LiveIndicator from '../components/LiveIndicator';
10	import { useRealtimeAlerts } from '../hooks/useRealtimeAlerts';
11	import { useToastContext } from '../components/Toast';
12	
13	// ─── Types ──────────────────────────────────────────────────
14	
15	interface AlertEvent {
16	    alert_id: string;
17	    action_id: string | null;
18	    context_id: string | null;
19	    customer_id: string;
20	    action_name: string | null;
21	    context_type: string | null;
22	    trend_delta: number | null;
23	    current_success_rate: number | null;
24	    previous_success_rate: number | null;
25	    total_attempts: number | null;
26	    detected_at: string;
27	    acknowledged: boolean;
28	    acknowledged_at: string | null;
29	    acknowledged_by: string | null;
30	    alert_type: string;
31	    severity: string;
32	    current_value: number | null;
33	    baseline_value: number | null;
34	    spike_ratio: number | null;
35	    affected_agent_count: number | null;
36	    message: string | null;
37	}
38	
39	type Severity = 'critical' | 'warning' | 'info';
40	type TimeRange = '24h' | '7d' | '30d';
41	
42	// ─── Design Tokens ──────────────────────────────────────────
43	
44	const COLORS = {
45	    bg: '#080b12',
46	    panel: '#0e1320',
47	    border: '#1e2d45',
48	    textPrimary: '#f0f4ff',
49	    textSecondary: '#8892a4',
50	    live: '#10b981',
51	    severity: {
52	        critical: { text: '#fca5a5', bg: 'rgba(239,68,68,0.12)', border: 'rgba(239,68,68,0.25)' },
53	        warning: { text: '#fcd34d', bg: 'rgba(245,158,11,0.12)', border: 'rgba(245,158,11,0.25)' },
54	        info: { text: '#93c5fd', bg: 'rgba(59,130,246,0.12)', border: 'rgba(59,130,246,0.25)' },
55	    } as Record<string, { text: string; bg: string; border: string }>,
56	};
57	
58	const FONT_MONO = "'IBM Plex Mono', 'JetBrains Mono', monospace";
59	const FONT_SANS = "'IBM Plex Sans', 'Inter', system-ui, sans-serif";
60	
61	// ─── Alert Type Mapping ─────────────────────────────────────
62	
63	const ALERT_TYPE_MAP: Record<string, { icon: string; label: string }> = {
64	    latency_spike: { icon: '⚡', label: 'Latency Spike' },
65	    context_drift: { icon: '🌀', label: 'Context Drift' },
66	    coordinated_failure: { icon: '⛔', label: 'Coordinated Failure' },
67	    degradation: { icon: '📉', label: 'Degradation' },
68	    score_flip: { icon: '🔄', label: 'Score Flip' },
69	};
70	
71	// ─── Helpers ────────────────────────────────────────────────
72	
73	function getStartDate(range: TimeRange): Date {
74	    const now = new Date();
75	    switch (range) {
76	        case '24h': return new Date(now.getTime() - 24 * 60 * 60 * 1000);
77	        case '7d': return new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
78	        case '30d': return new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
79	    }
80	}
81	
82	function formatRelativeTime(dateStr: string): string {
83	    const date = new Date(dateStr);
84	    const now = new Date();
85	    const diffMs = now.getTime() - date.getTime();
86	    const diffMin = Math.floor(diffMs / 60000);
87	    if (diffMin < 1) return 'just now';
88	    if (diffMin < 60) return `${diffMin}m ago`;
89	    const diffHrs = Math.floor(diffMin / 60);
90	    if (diffHrs < 24) return `${diffHrs}h ago`;
91	    const diffDays = Math.floor(diffHrs / 24);
92	    return `${diffDays}d ago`;
93	}
94	
95	function formatTime(dateStr: string): string {
96	    return new Date(dateStr).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
97	}
98	
99	function formatAbsolute(dateStr: string): string {
100	    return new Date(dateStr).toLocaleString();
101	}
102	
103	function getDateGroup(dateStr: string): string {
104	    const date = new Date(dateStr);
105	    const today = new Date();
106	    const yesterday = new Date(today);
107	    yesterday.setDate(yesterday.getDate() - 1);
108	
109	    if (date.toDateString() === today.toDateString()) return 'Today';
110	    if (date.toDateString() === yesterday.toDateString()) return 'Yesterday';
111	    return date.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric' });
112	}
113	
114	// ─── SeverityBadge ──────────────────────────────────────────
115	
116	function SeverityBadge({ severity }: { severity: string }) {
117	    const config = COLORS.severity[severity] ?? COLORS.severity.info;
118	    const icons: Record<string, string> = { critical: '⚠', warning: '●', info: 'ℹ' };
119	    const icon = icons[severity] ?? 'ℹ';
120	
121	    return (
122	        <span style={{
123	            display: 'inline-flex',
124	            alignItems: 'center',
125	            gap: '0.3rem',
126	            padding: '2px 8px',
127	            borderRadius: '9999px',
128	            fontSize: '0.7rem',
129	            fontWeight: 600,
130	            fontFamily: FONT_SANS,
131	            background: config.bg,
132	            color: config.text,
133	            border: `1px solid ${config.border}`,
134	            textTransform: 'uppercase',
135	            letterSpacing: '0.05em',
136	        }}>
137	            {icon} {severity}
138	        </span>
139	    );
140	}
141	
142	// ─── AlertTypeLabel ─────────────────────────────────────────
143	
144	function AlertTypeLabel({ alertType }: { alertType: string }) {
145	    const config = ALERT_TYPE_MAP[alertType] ?? { icon: '❓', label: alertType };
146	    return (
147	        <span style={{
148	            fontSize: '0.8rem',
149	            fontWeight: 600,
150	            fontFamily: FONT_SANS,
151	            color: COLORS.textPrimary,
152	        }}>
153	            {config.icon} {config.label}
154	        </span>
155	    );
156	}
157	
158	// ─── SummaryCard ────────────────────────────────────────────
159	
160	function SummaryCard({ label, count, severity }: { label: string; count: number; severity: string }) {
161	    const config = COLORS.severity[severity] ?? COLORS.severity.info;
162	    return (
163	        <div style={{
164	            display: 'flex',
165	            alignItems: 'center',
166	            gap: '0.5rem',
167	            padding: '0.6rem 1rem',
168	            borderRadius: '8px',
169	            background: config.bg,
170	            border: `1px solid ${config.border}`,
171	            minWidth: '100px',
172	        }}>
173	            <span style={{
174	                fontSize: '1.4rem',
175	                fontWeight: 700,
176	                fontFamily: FONT_MONO,
177	                color: config.text,
178	            }}>
179	                {count}
180	            </span>
181	            <span style={{
182	                fontSize: '0.75rem',
183	                fontWeight: 500,
184	                fontFamily: FONT_SANS,
185	                color: config.text,
186	                textTransform: 'uppercase',
187	                letterSpacing: '0.05em',
188	            }}>
189	                {label}
190	            </span>
191	        </div>
192	    );
193	}
194	
195	// ─── AlertCard ──────────────────────────────────────────────
196	
197	function AlertCard({ alert, onAcknowledge, isNew }: { alert: AlertEvent; onAcknowledge: (id: string) => void; isNew?: boolean }) {
198	    const [expanded, setExpanded] = useState(false);
199	
200	    const sevConfig = COLORS.severity[alert.severity] ?? COLORS.severity.info;
201	
202	    // Build metadata key-value pairs from typed columns
203	    const details: { label: string; value: string }[] = [];
204	    if (alert.action_name) details.push({ label: 'Action', value: alert.action_name });
205	    if (alert.context_type) details.push({ label: 'Context', value: alert.context_type });
206	    if (alert.trend_delta != null) details.push({ label: 'Trend Δ', value: `${(alert.trend_delta * 100).toFixed(1)}%` });
207	    if (alert.current_success_rate != null) details.push({ label: 'Current Rate', value: `${(alert.current_success_rate * 100).toFixed(1)}%` });
208	    if (alert.previous_success_rate != null) details.push({ label: 'Previous Rate', value: `${(alert.previous_success_rate * 100).toFixed(1)}%` });
209	    if (alert.current_value != null) details.push({ label: 'Current Value', value: `${alert.current_value.toLocaleString()}` });
210	    if (alert.baseline_value != null) details.push({ label: 'Baseline', value: `${alert.baseline_value.toLocaleString()}` });
211	    if (alert.spike_ratio != null) details.push({ label: 'Spike Ratio', value: `${alert.spike_ratio.toFixed(1)}×` });
212	    if (alert.affected_agent_count != null) details.push({ label: 'Affected Agents', value: `${alert.affected_agent_count}` });
213	    if (alert.total_attempts != null) details.push({ label: 'Attempts', value: `${alert.total_attempts}` });
214	
215	    return (
216	        <div
217	            style={{
218	                background: isNew ? 'rgba(16,185,129,0.08)' : COLORS.panel,
219	                border: `1px solid ${sevConfig.border}`,
220	                borderRadius: '8px',
221	                overflow: 'hidden',
222	                transition: 'background 2s ease-out, border-color 150ms',
223	            }}
224	        >
225	            {/* Collapsed header — always visible */}
226	            <button
227	                onClick={() => setExpanded(!expanded)}
228	                style={{
229	                    width: '100%',
230	                    display: 'flex',
231	                    alignItems: 'center',
232	                    gap: '0.75rem',
233	                    padding: '0.85rem 1rem',
234	                    background: 'none',
235	                    border: 'none',
236	                    cursor: 'pointer',
237	                    textAlign: 'left',
238	                    color: COLORS.textPrimary,
239	                    fontFamily: FONT_SANS,
240	                }}
241	            >
242	                <span style={{
243	                    fontSize: '0.75rem',
244	                    color: COLORS.textSecondary,
245	                    transform: expanded ? 'rotate(90deg)' : 'rotate(0deg)',
246	                    transition: 'transform 150ms',
247	                    flexShrink: 0,
248	                }}>
249	                    ▶
250	                </span>
251	
252	                <SeverityBadge severity={alert.severity} />
253	                <AlertTypeLabel alertType={alert.alert_type} />
254	
255	                <span style={{
256	                    flex: 1,
257	                    fontSize: '0.8rem',
258	                    color: COLORS.textSecondary,
259	                    overflow: 'hidden',
260	                    textOverflow: 'ellipsis',
261	                    whiteSpace: 'nowrap',
262	                    fontFamily: FONT_SANS,
263	                }}>
264	                    {alert.message ?? ''}
265	                </span>
266	
267	                {alert.acknowledged && (
268	                    <span style={{
269	                        fontSize: '0.7rem',
270	                        color: '#4a5568',
271	                        fontFamily: FONT_SANS,
272	                        flexShrink: 0,
273	                    }}>
274	                        ✓ ACK
275	                    </span>
276	                )}
277	
278	                <span
279	                    title={formatAbsolute(alert.detected_at)}
280	                    style={{
281	                        fontSize: '0.75rem',
282	                        color: COLORS.textSecondary,
283	                        fontFamily: FONT_MONO,
284	                        flexShrink: 0,
285	                        whiteSpace: 'nowrap',
286	                    }}
287	                >
288	                    {formatTime(alert.detected_at)}
289	                </span>
290	            </button>
291	
292	            {/* Expanded details */}
293	            {expanded && (
294	                <div style={{
295	                    padding: '0 1rem 1rem 2.75rem',
296	                    borderTop: `1px solid ${COLORS.border}`,
297	                }}>
298	                    {/* Message */}
299	                    {alert.message && (
300	                        <p style={{
301	                            fontSize: '0.82rem',
302	                            lineHeight: 1.5,
303	                            color: COLORS.textPrimary,
304	                            fontFamily: FONT_SANS,
305	                            margin: '0.75rem 0 0.5rem',
306	                        }}>
307	                            {alert.message}
308	                        </p>
309	                    )}
310	
311	                    {/* Detail key-value pairs */}
312	                    {details.length > 0 && (
313	                        <div style={{
314	                            display: 'grid',
315	                            gridTemplateColumns: 'auto 1fr',
