416	// ─── Code snippets per language ──────────────────────
417	function getBeforeCode(lang: 'node' | 'python' | 'curl', agentName: string): string {
418	        const resolvedAgentName = agentName || '<agent_id>';
419	        const resolvedApiBase = API_BASE ?? 'https://your-api-base.example.com';
420	
421	    if (lang === 'node') {
422	                return `const scores = await layerinfinite.getScores({
423	    context: { issue_type: '<issue_type>' }
424	});
425	agent.execute(scores.ranked_actions[0].action);`;
426	    }
427	    if (lang === 'python') {
428	        return `scores = layerinfinite.get_scores(
429	    context={"issue_type": "<issue_type>"}
430	)
431	agent.execute(scores["ranked_actions"][0]["action"])`;
432	    }
433	        return `curl -X GET ${resolvedApiBase}/v1/get-scores \\
434	    -H "Authorization: Bearer $LAYERINFINITE_API_KEY" \\
435	  -H "Content-Type: application/json" \\
436	    -d '{"agent_id":"${resolvedAgentName}","context":{"issue_type":"<issue_type>"}}'`;
437	}
438	
439	function getAfterCode(lang: 'node' | 'python' | 'curl'): string {
440	        const resolvedApiBase = API_BASE ?? 'https://your-api-base.example.com';
441	
442	    if (lang === 'node') {
443	        return `await layerinfinite.logOutcome({
444	    action: '<action_name>',
445	    success: <true_or_false>,
446	    response_ms: <response_time_ms>
447	});`;
448	    }
449	    if (lang === 'python') {
450	        return `layerinfinite.log_outcome(
451	    action="<action_name>",
452	    success=<true_or_false>,
453	    response_ms=<response_time_ms>
454	)`;
455	    }
456	        return `curl -X POST ${resolvedApiBase}/v1/log-outcome \\
457	    -H "Authorization: Bearer $LAYERINFINITE_API_KEY" \\
458	  -H "Content-Type: application/json" \\
459	    -d '{"action":"<action_name>","success":<true_or_false>,"response_ms":<response_time_ms>}'`;
460	}
461	
462	function CodeBlock({ code }: { code: string }) {
463	    return (
464	        <pre style={{
465	            background: '#0A0A0A',
466	            border: `1px solid ${C.border}`,
467	            padding: '14px 16px',
468	            fontFamily: FONT_MONO,
469	            fontSize: 11,
470	            color: C.muted,
471	            lineHeight: 1.7,
472	            margin: 0,
473	            overflow: 'auto',
474	            whiteSpace: 'pre-wrap',
475	            wordBreak: 'break-all',
476	        }}>
477	            {code}
478	        </pre>
479	    );
480	}
