8	import ScoreCard from '../components/ScoreCard';
9	import TrendBadge from '../components/TrendBadge';
10	
11	interface ActionScore {
12	    action_id: string;
13	    context_id: string;
14	    customer_id: string;
15	    action_name: string;
16	    action_category: string;
17	    raw_success_rate: number;
18	    weighted_success_rate: number;
19	    confidence: number;
20	    total_attempts: number;
21	    trend_delta: number | null;
