23	
24	export default function ScoreLeaderboard() {
25	    const [scores, setScores] = useState<ActionScore[]>([]);
26	    const [loading, setLoading] = useState(true);
27	    const [contextFilter, setContextFilter] = useState<string>('all');
28	
29	    useEffect(() => {
30	        fetchScores();
31	    }, []);
32	
33	    async function fetchScores() {
34	        setLoading(true);
