1	/**
2	 * Outcome History Page (/outcomes)
3	 * Data Source: fact_outcomes + joins to dim_actions, dim_agents, dim_contexts
4	 * Paginated, filterable by date/agent/context.
5	 */
6	import React, { useEffect, useState, useCallback } from 'react';
7	import { supabase } from '../supabaseClient';
8	import OutcomeTable from '../components/OutcomeTable';
9	import LiveIndicator from '../components/LiveIndicator';
10	import { useRealtimeOutcomes } from '../hooks/useRealtimeOutcomes';
11	
12	interface OutcomeRow {
13	    outcome_id: string;
14	    action_name: string;
15	    issue_type: string;
16	    success: boolean;
17	    timestamp: string;
18	    response_time_ms: number | null;
19	    agent_name: string;
20	    error_code: string | null;
21	}
22	
23	const PAGE_SIZE = 25;
24	
25	export default function OutcomeHistory() {
26	    const [outcomes, setOutcomes] = useState<OutcomeRow[]>([]);
27	    const [loading, setLoading] = useState(true);
28	    const [error, setError] = useState<string | null>(null);
29	    const [page, setPage] = useState(0);
30	    const [hasMore, setHasMore] = useState(true);
31	    const [filterSuccess, setFilterSuccess] = useState<'all' | 'true' | 'false'>('all');
32	
33	    const fetchOutcomes = useCallback(async () => {
34	        setLoading(true);
35	        setError(null);
36	
37	        let query = supabase
38	            .from('fact_outcomes')
39	            .select(`
40	                outcome_id, success, timestamp, response_time_ms, error_code,
41	                dim_actions!inner(action_name),
42	                dim_agents!inner(agent_name),
43	                dim_contexts!inner(issue_type)
44	            `)
45	            .eq('is_deleted', false)
46	            .eq('is_synthetic', false)
47	            .order('timestamp', { ascending: false })
48	            .range(page * PAGE_SIZE, (page + 1) * PAGE_SIZE - 1);
49	
50	        if (filterSuccess !== 'all') {
51	            query = query.eq('success', filterSuccess === 'true');
52	        }
53	
54	        const { data, error: queryError } = await query;
55	
56	        if (queryError) {
57	            setError(queryError.message);
58	            setOutcomes([]);
59	            setHasMore(false);
60	            setLoading(false);
61	            return;
62	        }
63	
64	        const mapped: OutcomeRow[] = (data ?? []).map((r: any) => ({
65	            outcome_id: r.outcome_id,
66	            action_name: r.dim_actions?.action_name ?? '',
67	            issue_type: r.dim_contexts?.issue_type ?? '',
68	            success: r.success,
69	            timestamp: r.timestamp,
70	            response_time_ms: r.response_time_ms,
71	            agent_name: r.dim_agents?.agent_name ?? '',
72	            error_code: r.error_code,
73	        }));
74	        setOutcomes(mapped);
75	        setHasMore(mapped.length === PAGE_SIZE);
76	        setLoading(false);
77	    }, [page, filterSuccess]);
78	
79	    useEffect(() => { void fetchOutcomes(); }, [fetchOutcomes]);
80	
81	    // ── Realtime ──────────────────────────────────────
82	
83	    const handleNewOutcome = useCallback(() => {
84	        // Only prepend on first page to avoid confusion
85	        if (page !== 0) return;
86	        void fetchOutcomes();
87	    }, [page, fetchOutcomes]);
88	
89	    const { isConnected } = useRealtimeOutcomes(handleNewOutcome);
90	
91	    return (
92	        <div>
93	            <style>{`
94	                @keyframes outcome-slide-in {
95	                    from { transform: translateY(-12px); opacity: 0; }
96	                    to   { transform: translateY(0); opacity: 1; }
97	                }
98	            `}</style>
99	            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
100	                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
101	                    <h1 style={{ fontSize: '1.5rem', fontWeight: 700, color: '#1e293b', margin: 0 }}>
102	                        Outcome History
103	                    </h1>
104	                    <LiveIndicator isConnected={isConnected} />
105	                </div>
106	                <div style={{ display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
107	                    <select
108	                        value={filterSuccess}
109	                        onChange={e => { setFilterSuccess(e.target.value as any); setPage(0); }}
110	                        style={{ padding: '0.4rem 0.8rem', borderRadius: '6px', border: '1px solid #cbd5e1', fontSize: '0.85rem' }}
111	                    >
112	                        <option value="all">All Results</option>
113	                        <option value="true">Successes Only</option>
114	                        <option value="false">Failures Only</option>
115	                    </select>
116	                </div>
117	            </div>
118	
119	            <OutcomeTable outcomes={outcomes} loading={loading} />
120	
121	            {!loading && error && (
122	                <div style={{ marginTop: '1rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: '0.75rem', padding: '0.75rem 1rem', borderRadius: '8px', border: '1px solid rgba(239,68,68,0.30)', background: 'rgba(239,68,68,0.10)', color: '#fca5a5' }}>
123	                    <span>{error}</span>
124	                    <button onClick={fetchOutcomes} style={{ ...btnStyle, color: '#fff', borderColor: '#334155', background: '#0f172a' }}>Retry</button>
125	                </div>
126	            )}
127	
128	            {!loading && !error && outcomes.length === 0 && (
129	                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', textAlign: 'center', padding: '4rem 1rem' }}>
130	                    <div style={{ fontSize: '2.5rem', opacity: 0.2, marginBottom: '0.75rem' }}>📋</div>
131	                    <h3 style={{ color: '#1e293b', margin: 0, fontSize: '1.1rem' }}>No outcomes logged yet</h3>
132	                    <p style={{ color: '#64748b', marginTop: '0.5rem', maxWidth: 420, lineHeight: 1.5 }}>
133	                        Every decision your agent makes is recorded here. Start logging outcomes to build your audit trail.
134	                    </p>
135	                </div>
136	            )}
137	
138	            {/* Pagination */}
139	            <div style={{ display: 'flex', justifyContent: 'center', gap: '1rem', marginTop: '1.5rem' }}>
140	                <button
141	                    onClick={() => setPage(p => Math.max(0, p - 1))}
142	                    disabled={page === 0}
143	                    style={btnStyle}
144	                >
145	                    ← Previous
146	                </button>
147	                <span style={{ color: '#64748b', fontSize: '0.85rem', lineHeight: '2.2' }}>Page {page + 1}</span>
148	                <button
149	                    onClick={() => setPage(p => p + 1)}
150	                    disabled={!hasMore}
151	                    style={btnStyle}
152	                >
153	                    Next →
154	                </button>
155	            </div>
156	        </div>
157	    );
158	}
159	
160	const btnStyle: React.CSSProperties = {
161	    padding: '0.4rem 1rem', borderRadius: '6px', border: '1px solid #cbd5e1',
162	    background: '#fff', cursor: 'pointer', fontSize: '0.85rem', color: '#475569',
163	};
