1	/**
2	 * Trust Status Page (/trust)
3	 * Data Source: agent_trust_scores + agent_trust_audit
4	 * Shows TrustGauge per agent, suspension log, reinstate button.
5	 */
6	import React, { useEffect, useState, useCallback } from 'react';
7	import { supabase } from '../supabaseClient';
8	import TrustGauge from '../components/TrustGauge';
9	import LiveIndicator from '../components/LiveIndicator';
10	import { useRealtimeTrust } from '../hooks/useRealtimeTrust';
11	import type { TrustRow as RealtimeTrustRow } from '../hooks/useRealtimeTrust';
12	import { useToastContext } from '../components/Toast';
13	
14	type TrustStatus = 'trusted' | 'probation' | 'sandbox' | 'suspended' | 'new';
15	
16	function normalizeTrustStatus(value: string | null | undefined): TrustStatus {
17	    const normalized = (value ?? '').toLowerCase();
18	    if (normalized === 'degraded') return 'sandbox';
19	    if (normalized === 'trusted' || normalized === 'probation' || normalized === 'sandbox' || normalized === 'suspended' || normalized === 'new') {
20	        return normalized;
21	    }
22	    return 'probation';
23	}
24	
25	interface TrustRow {
26	    trust_id: string;
27	    agent_id: string;
28	    trust_score: number;
29	    trust_status: TrustStatus;
30	    consecutive_failures: number;
31	    total_decisions: number;
32	    correct_decisions: number;
33	    agent_name?: string;
34	}
35	
36	interface AuditEvent {
37	    audit_id: string;
38	    agent_id: string;
39	    event_type: string;
40	    old_score: number | null;
41	    new_score: number | null;
42	    old_status: string | null;
43	    new_status: string | null;
44	    performed_by: string | null;
45	    reason: string | null;
46	    performed_at: string;
47	}
48	
49	export default function TrustStatus() {
50	    const [agents, setAgents] = useState<TrustRow[]>([]);
51	    const [auditLog, setAuditLog] = useState<AuditEvent[]>([]);
52	    const [loading, setLoading] = useState(true);
53	    const [flashAgentId, setFlashAgentId] = useState<string | null>(null);
54	    const { showToast } = useToastContext();
55	
56	    useEffect(() => { fetchData(); }, []);
57	
58	    // ── Realtime trust updates ──────────────────────
59	
60	    const handleTrustChange = useCallback((incoming: RealtimeTrustRow) => {
61	        setAgents((prev) => {
62	            const idx = prev.findIndex((a) => a.agent_id === incoming.agent_id);
63	            if (idx >= 0) {
64	                // UPDATE: replace in-place
65	                const updated = [...prev];
66	                updated[idx] = { ...updated[idx], ...incoming, trust_status: normalizeTrustStatus(incoming.trust_status) };
67	                return updated;
68	            }
69	            // INSERT: new agent
70	            return [...prev, {
71	                ...incoming,
72	                trust_status: normalizeTrustStatus(incoming.trust_status),
73	                agent_name: incoming.agent_id.slice(0, 8),
74	            }];
75	        });
76	
77	        // Flash the gauge
78	        setFlashAgentId(incoming.agent_id);
79	        setTimeout(() => setFlashAgentId(null), 1500);
80	
81	        // Suspension warning
82	        if (incoming.trust_score < 0.3) {
83	            showToast(
84	                `Agent ${incoming.agent_id.slice(0, 8)} trust dropped to ${(incoming.trust_score * 100).toFixed(1)}% — suspended`,
85	                'critical',
86	                8000,
87	            );
88	        }
89	    }, [showToast]);
90	
91	    const { isConnected } = useRealtimeTrust(handleTrustChange);
92	
93	    async function fetchData() {
94	        setLoading(true);
95	
96	        // Fetch trust scores with agent names
97	        const { data: trustData } = await supabase
98	            .from('agent_trust_scores')
99	            .select(`
100	                trust_id, agent_id, trust_score, trust_status, consecutive_failures,
101	                total_decisions, correct_decisions,
102	                dim_agents!inner(agent_name)
103	            `)
104	            .order('trust_score', { ascending: true });
105	
106	        if (trustData) {
107	            setAgents(trustData.map((r: any) => ({
108	                ...r,
109	                trust_status: normalizeTrustStatus(r.trust_status),
110	                agent_name: r.dim_agents?.agent_name ?? r.agent_id.slice(0, 8),
111	            })));
112	        }
113	
114	        // Fetch recent audit events
115	        const { data: auditData } = await supabase
116	            .from('agent_trust_audit')
117	            .select('*')
118	            .order('performed_at', { ascending: false })
119	            .limit(50);
120	
121	        if (auditData) setAuditLog(auditData as AuditEvent[]);
122	
123	        setLoading(false);
124	    }
125	
126	    if (loading) {
127	        return <div style={{ color: '#94a3b8', textAlign: 'center', padding: '3rem' }}>Loading trust data...</div>;
128	    }
129	
130	    return (
131	        <div>
132	            <style>{`
133	                @keyframes trust-flash {
134	                    0%   { box-shadow: 0 0 0 0 rgba(59,130,246,0.4); }
135	                    50%  { box-shadow: 0 0 12px 4px rgba(59,130,246,0.3); }
136	                    100% { box-shadow: 0 0 0 0 rgba(59,130,246,0); }
137	                }
138	            `}</style>
139	            <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1.5rem' }}>
140	                <h1 style={{ fontSize: '1.5rem', fontWeight: 700, color: '#1e293b', margin: 0 }}>
141	                    Agent Trust Status
142	                </h1>
143	                <LiveIndicator isConnected={isConnected} />
144	            </div>
145	
146	            {/* Trust gauges */}
147	            {agents.length === 0 ? (
148	                <div style={{ color: '#94a3b8', textAlign: 'center', padding: '2rem' }}>No agents found.</div>
149	            ) : (
150	                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1rem', marginBottom: '2rem' }}>
151	                    {agents.map(a => (
152	                        <div
153	                            key={a.trust_id}
154	                            style={{
155	                                animation: flashAgentId === a.agent_id ? 'trust-flash 1.5s ease-out' : 'none',
156	                                borderRadius: '8px',
157	                            }}
158	                        >
159	                            <TrustGauge
160	                                agentName={a.agent_name ?? a.agent_id.slice(0, 8)}
161	                                trustScore={a.trust_score}
162	                                trustStatus={a.trust_status}
163	                                consecutiveFailures={a.consecutive_failures}
164	                                totalDecisions={a.total_decisions}
165	                                correctDecisions={a.correct_decisions}
166	                            />
167	                        </div>
168	                    ))}
169	                </div>
170	            )}
171	
172	            {/* Trust audit log */}
173	            <h2 style={{ fontSize: '1.1rem', fontWeight: 600, color: '#1e293b', marginBottom: '1rem', borderTop: '1px solid #e2e8f0', paddingTop: '1.5rem' }}>
174	                Trust Audit Log
175	            </h2>
176	
177	            {auditLog.length === 0 ? (
178	                <div style={{ color: '#94a3b8', textAlign: 'center', padding: '1rem' }}>No audit events recorded.</div>
179	            ) : (
180	                <div style={{ overflowX: 'auto' }}>
181	                    <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.82rem' }}>
182	                        <thead>
183	                            <tr style={{ background: '#f8fafc', borderBottom: '2px solid #e2e8f0' }}>
184	                                <th style={th}>Time</th>
185	                                <th style={th}>Event</th>
186	                                <th style={th}>Agent</th>
187	                                <th style={th}>Score Δ</th>
188	                                <th style={th}>Status Δ</th>
189	                                <th style={th}>Performed By</th>
190	                                <th style={th}>Reason</th>
191	                            </tr>
192	                        </thead>
193	                        <tbody>
194	                            {auditLog.map(e => (
195	                                <tr key={e.audit_id} style={{ borderBottom: '1px solid #f1f5f9' }}>
196	                                    <td style={td}>{new Date(e.performed_at).toLocaleString()}</td>
197	                                    <td style={td}>
198	                                        <span style={{
199	                                            padding: '1px 6px', borderRadius: '9999px', fontSize: '0.72rem', fontWeight: 600,
200	                                            background: eventColor(e.event_type).bg,
201	                                            color: eventColor(e.event_type).fg,
202	                                        }}>{e.event_type}</span>
203	                                    </td>
204	                                    <td style={{ ...td, fontFamily: 'monospace', fontSize: '0.75rem' }}>{e.agent_id.slice(0, 8)}</td>
205	                                    <td style={td}>
206	                                        {e.old_score !== null && e.new_score !== null
207	                                            ? `${(e.old_score * 100).toFixed(1)}% → ${(e.new_score * 100).toFixed(1)}%`
208	                                            : '—'}
209	                                    </td>
210	                                    <td style={td}>
211	                                        {e.old_status && e.new_status ? `${e.old_status} → ${e.new_status}` : e.new_status ?? '—'}
212	                                    </td>
213	                                    <td style={{ ...td, color: '#64748b' }}>{e.performed_by ?? '—'}</td>
214	                                    <td style={{ ...td, color: '#94a3b8', maxWidth: '250px', overflow: 'hidden', textOverflow: 'ellipsis' }}>
215	                                        {e.reason ?? '—'}
216	                                    </td>
217	                                </tr>
218	                            ))}
219	                        </tbody>
220	                    </table>
221	                </div>
222	            )}
223	        </div>
224	    );
225	}
226	
227	function eventColor(type: string): { bg: string; fg: string } {
228	    switch (type) {
229	        case 'suspended': return { bg: '#fef2f2', fg: '#dc2626' };
230	        case 'reinstated': return { bg: '#f0fdf4', fg: '#16a34a' };
231	        case 'recalibrated': return { bg: '#fff7ed', fg: '#ea580c' };
232	        case 'created': return { bg: '#eff6ff', fg: '#3b82f6' };
233	        default: return { bg: '#f1f5f9', fg: '#64748b' };
234	    }
