39	// ─── Typing animation hook ──────────────────────────
40	function useTerminalAnimation() {
41	    const [visibleLines, setVisibleLines] = useState<Array<{ text: string; style: React.CSSProperties }>>([]);
42	    const [typingText, setTypingText] = useState('');
43	    const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
44	
45	    useEffect(() => {
46	        let step = 0;
47	        let charIdx = 0;
48	        let lineBuffer: Array<{ text: string; style: React.CSSProperties }> = [];
49	        let paused = false;
50	
51	        const tick = () => {
52	            if (paused) return;
53	
54	            if (step === 0) {
55	                // Typing first command
56	                const cmd = TERMINAL_STEPS[0].text as string;
57	                if (charIdx <= cmd.length) {
58	                    setTypingText(cmd.slice(0, charIdx));
59	                    charIdx++;
60	                } else {
61	                    lineBuffer = [{ text: cmd, style: { color: C.accent, fontFamily: FONT_MONO, fontSize: 12 } }];
62	                    setVisibleLines([...lineBuffer]);
63	                    setTypingText('');
64	                    step = 1;
65	                    charIdx = 0;
66	                }
67	            } else if (step === 1) {
68	                // Show response lines one by one
69	                const resp = TERMINAL_STEPS[1];
70	                if (charIdx < resp.lines!.length) {
71	                    const l = resp.lines![charIdx];
72	                    lineBuffer.push({
73	                        text: `  ${l.icon} ${l.text.padEnd(16)} score: ${l.score}  ${l.note}`,
74	                        style: { color: l.color, fontFamily: FONT_MONO, fontSize: 12 },
75	                    });
76	                    setVisibleLines([...lineBuffer]);
77	                    charIdx++;
78	                } else {
79	                    step = 2;
80	                    charIdx = 0;
81	                }
82	            } else if (step === 2) {
83	                // Typing second command
84	                const cmd = TERMINAL_STEPS[2].text as string;
85	                if (charIdx <= cmd.length) {
86	                    setTypingText(cmd.slice(0, charIdx));
87	                    charIdx++;
88	                } else {
89	                    lineBuffer.push({ text: cmd, style: { color: C.accent, fontFamily: FONT_MONO, fontSize: 12 } });
90	                    setVisibleLines([...lineBuffer]);
91	                    setTypingText('');
92	                    step = 3;
93	                    charIdx = 0;
94	                }
95	            } else if (step === 3) {
96	                // Show result
97	                if (charIdx === 0) {
98	                    lineBuffer.push({
99	                        text: TERMINAL_STEPS[3].text!,
100	                        style: { color: C.accent, fontFamily: FONT_MONO, fontSize: 12 },
101	                    });
102	                    setVisibleLines([...lineBuffer]);
103	                    charIdx = 1;
104	                } else if (charIdx < 20) {
105	                    charIdx++;
106	                } else {
107	                    // Reset
108	                    paused = true;
109	                    setTimeout(() => {
110	                        lineBuffer = [];
111	                        setVisibleLines([]);
112	                        setTypingText('');
113	                        step = 0;
114	                        charIdx = 0;
115	                        paused = false;
116	                    }, 1200);
117	                }
118	            }
119	        };
120	
121	        intervalRef.current = setInterval(tick, 80);
122	        return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
123	    }, []);
124	
125	    return { visibleLines, typingText };
126	}
