141	function FeaturesGrid(): React.ReactElement {
142	  const cardRefs = useRef<(HTMLDivElement | null)[]>([]);
143	
144	  useEffect(() => {
145	    const observer = new IntersectionObserver(
146	      (entries) => {
147	        entries.forEach((entry) => {
148	          if (!entry.isIntersecting) return;
149	          const el = entry.target as HTMLElement;
150	          const delay = el.dataset.delay ?? '0';
151	          el.style.transitionDelay = `${delay}s`;
152	          el.classList.add('feat-visible');
153	          observer.unobserve(el);
154	        });
155	      },
156	      { threshold: 0.08 }
157	    );
158	
159	    cardRefs.current.forEach((c) => { if (c) observer.observe(c); });
160	
161	    // Trigger for cards already in viewport on load
162	    const onLoad = () => {
163	      cardRefs.current.forEach((c) => {
164	        if (!c) return;
165	        const rect = c.getBoundingClientRect();
166	        if (rect.top < window.innerHeight * 0.95) {
167	          const delay = c.dataset.delay ?? '0';
168	          c.style.transitionDelay = `${delay}s`;
169	          c.classList.add('feat-visible');
170	          observer.unobserve(c);
171	        }
172	      });
173	    };
174	    window.addEventListener('load', onLoad);
175	    onLoad();
176	    return () => window.removeEventListener('load', onLoad);
177	  }, []);
178	
179	  return (
180	    <div
181	      className="relative grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 border border-[#1a1a24] rounded-[20px] overflow-hidden"
182	      style={{ isolation: 'isolate' }}
183	    >
184	      {/* inner top glow */}
185	      <div
186	        className="pointer-events-none absolute inset-0 rounded-[20px] z-0"
187	        style={{
188	          background: 'radial-gradient(ellipse 60% 40% at 50% 0%, rgba(0,255,133,0.03) 0%, transparent 70%)',
189	        }}
190	      />
191	
192	      {FEATURES.map((f, i) => {
193	        const isLastCol   = (i + 1) % 3 === 0;
194	        const isLastRow   = i >= 3;
195	        const isMd2nd     = (i + 1) % 2 === 0;   // 2nd col on md
196	        const isMdLastRow = i >= 4;               // last row on md (5, 6)
197	
198	        return (
199	          <div
200	            key={f.title}
201	            ref={(el) => { cardRefs.current[i] = el; }}
202	            data-delay={String((i + 1) * 0.05)}
203	            className={[
204	              'feat-card group relative z-10 p-10 cursor-default',
205	              // right border — all except last col on xl
206	              !isLastCol ? 'xl:border-r border-[#1a1a24]' : '',
207	              // right border on md (2-col): remove every 2nd
208	              !isMd2nd ? 'md:border-r border-[#1a1a24]' : 'md:border-r-0',
209	              // bottom border — all except last row on xl
210	              !isLastRow ? 'xl:border-b border-[#1a1a24]' : 'xl:border-b-0',
211	              // bottom border on md: rows 1-4 get it, last row doesn't
212	              !isMdLastRow ? 'md:border-b border-[#1a1a24]' : 'md:border-b-0',
213	              // mobile: always bottom border, remove on last card
214	              i < FEATURES.length - 1 ? 'border-b border-[#1a1a24]' : '',
215	            ].join(' ')}
216	          >
217	            {/* icon */}
218	            <div className="mb-6 flex h-11 w-11 items-center justify-center rounded-xl border border-white/[0.06] bg-[#1a1a24] text-[#555555] transition-all duration-200 group-hover:border-[#00FF85]/20 group-hover:bg-[#00FF85]/10 group-hover:text-[#00FF85]">
