23	type FilterTab = 'all' | 'pending' | 'resolved';
24	
25	function isPending(row: SignalRow): boolean {
26	    return !row.resolved_at;
27	}
28	
29	function getQueuedTimestamp(row: SignalRow): string | null {
30	    return row.queued_at ?? row.registered_at ?? row.created_at ?? null;
31	}
32	
33	function getActionLabel(row: SignalRow): string {
34	    if (row.action_name && row.action_name.trim().length > 0) return row.action_name;
35	    if (row.outcome_id) return `outcome:${row.outcome_id.slice(-8)}`;
36	    return 'unknown_action';
37	}
38	
39	function getConfidence(row: SignalRow): number | null {
40	    if (typeof row.confidence === 'number' && Number.isFinite(row.confidence)) {
41	        return Math.max(0, Math.min(1, row.confidence));
42	    }
43	    return null;
44	}
45	
46	function getResolvedOutcome(row: SignalRow): 'SUCCESS' | 'FAILURE' | 'UNKNOWN' {
47	    if (row.outcome_derived == null && getConfidence(row) === null) {
48	        return 'UNKNOWN';
49	    }
50	    if (row.outcome_derived === true) return 'SUCCESS';
51	    if (row.outcome_derived === false) return 'FAILURE';
52	    const confidence = getConfidence(row);
53	    return confidence !== null && confidence >= 0.5 ? 'SUCCESS' : 'FAILURE';
54	}
