56	function getHttpStatusBadgeClass(status: number | null | undefined): string {
57	    if (typeof status !== 'number') {
58	        return 'inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium bg-yellow-500/10 text-yellow-400 border border-yellow-500/20';
59	    }
