69	function getConfidenceClass(value: number | null): string {
70	    if (value === null) return 'text-[#a1a1aa]';
71	    if (value >= 0.7) return 'text-[#b8ff00]';
72	    if (value >= 0.4) return 'text-[#facc15]';
73	    return 'text-[#ff4444]';
