27	// ── FIX: Parse action name from the reason field ──────────────
28	// agent_trust_audit has no action_name column.
29	// The action is embedded in the reason string in two formats:
30	//   "Outcome success via SDK: send_refund_email"    → "send_refund_email"
31	//   "Outcome failure recorded: qa_test_no_episode"  → "qa_test_no_episode"
32	// Returns null for status-change rows (no action embedded).
33	function parseActionFromReason(reason: string | null | undefined): string | null {
34	  if (!reason) return null;
35	  const sdkMatch = reason.match(/via\s+SDK:\s*(.+)$/i);
36	  if (sdkMatch) return sdkMatch[1].trim();
37	  const recordedMatch = reason.match(/recorded:\s*(.+)$/i);
38	  if (recordedMatch) return recordedMatch[1].trim();
39	  return null;
40	}
41	
42	// ── FIX: Human-readable label for status-change audit rows ────
43	// Trust-updater writes these reason strings on status changes:
44	//   "Trust probation → trusted"
45	//   "Auto-suspended: score=0.210, failures=5"
46	//   "Batch recalculation: processed 12 outcomes"
47	// These are policy events, not action rows — show a clear label.
48	function parseStatusLabel(reason: string | null | undefined): string | null {
49	  if (!reason) return null;
50	  const arrowMatch = reason.match(/(\w+)\s*→\s*(\w+)/);
51	  if (arrowMatch) return `Trust recalibrated: ${arrowMatch[1]} → ${arrowMatch[2]}`;
52	  if (/auto-suspended/i.test(reason)) return 'Auto-suspended by policy';
53	  if (/batch recalculation/i.test(reason)) return 'Batch recalibration';
54	  if (/reinstat/i.test(reason)) return 'Agent reinstated';
55	  return null;
56	}
