167	function pct(value: number | null | undefined, decimals = 1): string {
168	    if (value === null || value === undefined || !Number.isFinite(value)) return '—';
169	    return `${(value * 100).toFixed(decimals)}%`;
170	}
171	
172	function relTime(iso: string | null | undefined): string {
173	    if (!iso) return '—';
174	    const deltaMs = Date.now() - new Date(iso).getTime();
175	    const hours = Math.floor(deltaMs / 3_600_000);
176	    if (hours < 1) return 'just now';
177	    if (hours < 24) return `${hours}h ago`;
178	    const days = Math.floor(hours / 24);
179	    if (days < 30) return `${days}d ago`;
180	    return `${Math.floor(days / 30)}mo ago`;
181	}
182	
183	function confidenceLabel(label: ConfidenceLabel): { text: string; cls: string } {
184	    if (label === 'very_high') return { text: 'Very high', cls: `bg-[${ACCENT}]/10 text-[${ACCENT}] border-[${ACCENT}]/30` };
185	    if (label === 'high') return { text: 'High', cls: `bg-[${ACCENT}]/10 text-[${ACCENT}] border-[${ACCENT}]/30` };
186	    if (label === 'medium') return { text: 'Medium', cls: 'bg-yellow-500/10 text-yellow-400 border-yellow-500/30' };
187	    if (label === 'low') return { text: 'Low', cls: 'bg-red-500/10 text-red-400 border-red-500/30' };
188	    return { text: 'None', cls: 'bg-[#1a1a24] text-[#52525b] border-[#1a1a24]' };
189	}
190	
191	function confidenceTier(effectiveSamples: number): { label: string; cls: string } {
192	    if (effectiveSamples >= 100) return { label: 'Tier 1 — Stable', cls: 'text-[#b8ff00]' };
193	    if (effectiveSamples >= 50) return { label: 'Tier 2 — Warming', cls: 'text-yellow-400' };
194	    if (effectiveSamples >= 10) return { label: 'Tier 3 — Early', cls: 'text-orange-400' };
195	    return { label: 'Cold Start', cls: 'text-[#52525b]' };
196	}
