198	// ─── Micro sparkline ─────────────────────────────────────────────────────────
199	
200	function Sparkline({ points, direction }: { points: Array<{ rate: number }>; direction: TrendDirection }): React.ReactElement | null {
201	    if (points.length < 2) return null;
202	
203	    const W = 120;
204	    const H = 36;
205	    const pad = 4;
206	    const rates = points.map((p) => p.rate);
207	    const min = Math.min(...rates);
208	    const max = Math.max(...rates);
209	    const range = max - min || 0.01;
210	
211	    const toX = (i: number) => pad + (i / (points.length - 1)) * (W - pad * 2);
212	    const toY = (r: number) => H - pad - ((r - min) / range) * (H - pad * 2);
213	
214	    const d = rates.map((r, i) => `${i === 0 ? 'M' : 'L'} ${toX(i).toFixed(1)} ${toY(r).toFixed(1)}`).join(' ');
215	    const fillD = `${d} L ${toX(rates.length - 1).toFixed(1)} ${H} L ${toX(0).toFixed(1)} ${H} Z`;
216	
217	    const stroke =
218	        direction === 'improving' ? ACCENT :
219	            direction === 'degrading' ? '#f87171' :
220	                '#52525b';
221	
222	    return (
223	        <svg width={W} height={H} className="overflow-visible">
224	            <defs>
225	                <linearGradient id="grad-degrade" x1="0" y1="0" x2="0" y2="1">
226	                    <stop offset="0%" stopColor="#f87171" stopOpacity="0.25" />
227	                    <stop offset="100%" stopColor="#f87171" stopOpacity="0" />
228	                </linearGradient>
229	            </defs>
230	            {direction === 'degrading' && (
231	                <path d={fillD} fill="url(#grad-degrade)" stroke="none" />
232	            )}
233	            <line x1={0} y1={H} x2={W} y2={H} stroke="#52525b" strokeWidth="1" strokeDasharray="3 3" opacity={0.5} />
234	            <path d={d} fill="none" stroke={stroke} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
235	        </svg>
236	    );
237	}
