555	function DriftAlert({ analytics }: { analytics: TaskAnalytics }): React.ReactElement | null {
556	    const { drift } = analytics;
557	    
558	    // Noise Gate: Hide alert if statistical confidence in the trend is too weak (R² < 0.25)
559	    if (drift.direction !== 'degrading' || drift.slope === null || drift.confidence === null || drift.confidence < 0.25) {
560	        return null;
561	    }
562	
563	    // Explode the pain point: Show total drop across window, not drop per outcome
564	    const totalDropPct = Math.abs(drift.slope * drift.window_size * 100).toFixed(1);
565	
566	    return (
567	        <div className="flex items-start gap-3 bg-red-500/5 border border-red-500/30 rounded-2xl p-4">
568	            <TrendingDown size={16} className="text-red-400 mt-0.5 shrink-0" />
