570	                <div className="flex flex-wrap items-center gap-2">
571	                    <p className="text-sm font-bold text-red-500">Critical Context Drift</p>
572	                    <span className="px-2 py-0.5 bg-red-500/20 rounded-md text-[10px] font-bold text-red-300 border border-red-500/20 uppercase tracking-widest">
573	                        {totalDropPct}% Plunge
574	                    </span>
575	                </div>
576	                <p className="text-xs text-red-200/80 leading-relaxed">
577	                    The success rate for this task has cumulatively plunged by <strong className="text-red-400">{totalDropPct}%</strong> over the last {drift.window_size} executions (R² = {drift.confidence.toFixed(2)}). 
578	                    The environment has fundamentally changed. If your agent is hardcoded to a single action, it is rapidly failing.
579	                </p>
580	                {drift.points.length >= 2 && (
581	                    <div className="pt-3 pb-1">
582	                        <Sparkline points={drift.points} direction="degrading" />
583	                    </div>
584	                )}
585	            </div>
586	        </div>
587	    );
588	}
