691	
692	function ActionLeaderboard({
693	    actions,
694	    bestActionName,
695	    totalOutcomes,
696	}: {
697	    actions: ActionPerformance[];
698	    bestActionName: string | null;
699	    totalOutcomes: number;
700	}): React.ReactElement {
701	    // Deduplicate by action_id (server already deduplicates, this is a safety net).
702	    // If two entries share the same action_name but different IDs (normalization lag),
703	    // keep the one with the higher total_count as it has more evidence.
704	    const seenIds = new Set<string>();
705	    const seenNames = new Map<string, ActionPerformance>();
706	    const deduped: ActionPerformance[] = [];
707	    for (const a of actions) {
708	        if (seenIds.has(a.action_id)) continue;
709	        seenIds.add(a.action_id);
710	        const existing = seenNames.get(a.action_name);
711	        if (existing) {
712	            if (a.total_count > existing.total_count) {
713	                deduped.splice(deduped.indexOf(existing), 1, a);
714	                seenNames.set(a.action_name, a);
715	            }
716	        } else {
717	            seenNames.set(a.action_name, a);
718	            deduped.push(a);
719	        }
720	    }
721	    const sorted = deduped.sort((a, b) => b.resolution_rate - a.resolution_rate);
722	
723	    if (sorted.length === 0) {
724	        return (
725	            <div className="bg-[#111118] border border-[#1a1a24] rounded-2xl p-5 space-y-2">
726	                <p className="text-xs font-semibold text-white">Action Leaderboard</p>
727	                <p className="text-xs text-[#52525b]">No action-level outcomes logged for this task yet.</p>
728	            </div>
729	        );
730	    }
731	
732	    const best = sorted[0]!;
733	    const worst = sorted[sorted.length - 1]!;
734	    const delta = sorted.length >= 2 ? best.resolution_rate - worst.resolution_rate : null;
735	
736	    return (
737	        <div className="bg-[#111118] border border-[#1a1a24] rounded-2xl overflow-hidden">
738	            <div className="px-5 py-4 border-b border-[#1a1a24] space-y-1">
739	                <p className="text-xs font-semibold text-white">Action Leaderboard — What Works</p>
740	                <p className="text-[10px] text-[#52525b]">
741	                    Ranked by resolution rate (weighted outcome score). Confidence tier shows statistical reliability of each score.
742	                </p>
743	                {delta !== null && (
744	                    <p className="text-[10px] text-[#a1a1aa]">
745	                        Performance gap: <span className="text-[#b8ff00] font-mono">{pct(delta)}</span> between best and worst action.
746	                        {delta >= 0.1 && ' Switching to the top action can meaningfully improve resolution.'}
747	                    </p>
748	                )}
749	            </div>
750	
751	            <div className="overflow-x-auto">
752	                <table className="w-full text-xs">
753	                    <thead>
754	                        <tr className="border-b border-[#1a1a24] text-[#52525b] text-[10px] uppercase tracking-wider">
755	                            <th className="text-left px-5 py-2.5 font-medium">Action</th>
756	                            <th className="text-left px-4 py-2.5 font-medium min-w-[120px]">Win Rate</th>
757	                            <th className="text-right px-4 py-2.5 font-medium">Attempts</th>
758	                            <th className="text-right px-4 py-2.5 font-medium">Confidence Tier</th>
759	                            <th className="text-right px-5 py-2.5 font-medium">Last Seen</th>
760	                        </tr>
761	                    </thead>
762	                    <tbody className="divide-y divide-[#1a1a24]">
763	                        {sorted.map((action, rank) => {
764	                            const isRecommended = action.action_name === bestActionName;
765	                            const tier = confidenceTier(action.effective_sample_count ?? action.total_count);
766	                            const share = totalOutcomes > 0 ? action.total_count / totalOutcomes : 0;
767	                            const conv = action.semantic_cluster_convergence ?? null;
768	
769	                            return (
770	                                <tr
771	                                    key={action.action_id}
772	                                    className={`transition-colors ${isRecommended ? 'bg-[#0f1a00]' : 'hover:bg-[#0f0f18]'}`}
773	                                >
774	                                    {/* Action name */}
775	                                    <td className="px-5 py-3">
776	                                        <div className="flex items-center gap-2">
777	                                            <span className="text-[10px] text-[#3f3f46] font-mono w-4 shrink-0">
778	                                                #{rank + 1}
779	                                            </span>
780	                                            <span className={`font-mono font-medium truncate max-w-[160px] ${isRecommended ? 'text-[#b8ff00]' : 'text-white'}`}>
781	                                                {action.action_name}
782	                                            </span>
783	                                            {isRecommended && (
784	                                                <span className="text-[9px] px-1.5 py-0.5 bg-[#b8ff00]/15 text-[#b8ff00] border border-[#b8ff00]/30 rounded-full shrink-0">
785	                                                    BEST
786	                                                </span>
787	                                            )}
788	                                        </div>
789	                                        {/* Share bar */}
790	                                        <div className="mt-1.5 ml-6 h-1 rounded-full bg-[#1a1a24] overflow-hidden w-32">
791	                                            <div
792	                                                className={`h-full rounded-full ${isRecommended ? 'bg-[#b8ff00]' : 'bg-[#3f3f46]'}`}
793	                                                style={{ width: `${(share * 100).toFixed(1)}%` }}
794	                                            />
795	                                        </div>
796	                                    </td>
797	
798	                                    {/* Win rate */}
799	                                    <td className="px-4 py-3">
800	                                        <div className="flex items-center gap-3">
801	                                            <span className={`font-mono font-semibold w-10 ${isRecommended ? 'text-[#b8ff00]' : 'text-white'}`}>
802	                                                {pct(action.resolution_rate)}
803	                                            </span>
804	                                            <div className="flex-1 h-1.5 bg-[#1a1a24] rounded-full overflow-hidden min-w-[50px]">
805	                                                <div 
806	                                                    className={`h-full rounded-full transition-all ${isRecommended ? 'bg-[#b8ff00]' : 'bg-[#52525b]'}`}
807	                                                    style={{ width: `${action.resolution_rate * 100}%` }}
808	                                                />
809	                                            </div>
810	                                        </div>
811	                                    </td>
812	
813	                                    {/* Attempts */}
814	                                    <td className="px-4 py-3 text-right text-[#a1a1aa] font-mono">
815	                                        {action.total_count.toLocaleString()}
816	                                    </td>
817	
818	                                    {/* Confidence tier */}
819	                                    <td className="px-4 py-3 text-right">
820	                                        <span className={`text-[10px] ${tier.cls}`}>{tier.label}</span>
821	                                    </td>
822	
823	                                    {/* Last seen */}
824	                                    <td className="px-5 py-3 text-right text-[10px] text-[#52525b]">
825	                                        {relTime(action.last_seen_at)}
826	                                    </td>
827	                                </tr>
828	                            );
829	                        })}
830	                    </tbody>
831	                </table>
832	            </div>
833	        </div>
834	    );
835	}
