837	// ─── Engine interventions ─────────────────────────────────────────────────────
838	
839	function EngineInterventions({
840	    analytics,
841	    rec,
842	}: {
843	    analytics: TaskAnalytics;
844	    rec: RecommendationResponse;
845	}): React.ReactElement | null {
846	    const { explore_exploit, trust_blocks } = analytics;
847	    const exploreRatio = explore_exploit.explore_ratio;
848	    const trustBlockRate = trust_blocks.total > 0 ? trust_blocks.blocked_count / trust_blocks.total : 0;
849	
850	    const noiseGate = rec.noise_gate;
851	    const silentWarning = rec._silent_failure_warning ?? false;
852	    const cohortBand = rec.cohort_reliability?.band ?? null;
853	    const bandCls = cohortBand === 'stable' ? 'text-[#b8ff00]' : cohortBand === 'anomalous' ? 'text-red-400' : 'text-yellow-400';
854	
855	    // Exception-based UI: Hide this entire panel if the engine is operating cleanly with 0 interventions
856	    const hasExplore = exploreRatio !== null && exploreRatio > 0;
857	    const hasBlocks = trust_blocks.blocked_count > 0;
858	    const isAnomalous = cohortBand !== 'stable' && cohortBand !== null;
859	    const hasWarnings = silentWarning || noiseGate?.is_noisy_task;
860	
861	    if (!hasExplore && !hasBlocks && !isAnomalous && !hasWarnings) {
862	        return null;
863	    }
