1	/**
2	 * Layerinfinite — lib/api.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Shared fetch utility for agent API routes (/v1/*).
5	 *
6	 * API CALL RULE: All calls to /v1/* MUST use the agent API key from localStorage.
7	 * NEVER use supabase.auth.getSession() token for agent routes.
8	 * Use the createAgentFetch() helper below which enforces this and handles 401 globally.
9	 *
10	 * Usage:
11	 *   const agentFetch = createAgentFetch(apiKey, handleAuthFailure);
12	 *   const res = await agentFetch(`${API_BASE}/v1/me`);
13	 * ══════════════════════════════════════════════════════════════
14	 */
15	
16	/**
17	 * Creates a fetch wrapper that:
18	 * 1. Always attaches the agent API key as X-API-Key header
19	 * 2. On 401 or 403: calls onAuthFailure() (which should clear the key + redirect)
20	 *
21	 * @param apiKey - The layerinfinite_XXXX key from localStorage
22	 * @param onAuthFailure - Callback to invoke on auth failure (typically handleAuthFailure from useAgentApiKey)
23	 */
24	export function createAgentFetch(
25	  apiKey: string,
26	  onAuthFailure: () => void
27	): (url: string, options?: RequestInit) => Promise<Response> {
28	  return async (url: string, options: RequestInit = {}): Promise<Response> => {
29	    const headers = new Headers(options.headers ?? {});
30	    headers.set('X-API-Key', apiKey);
31	
32	    const isFormData = typeof FormData !== 'undefined' && options.body instanceof FormData;
33	    if (isFormData) {
34	      // Let the browser set multipart/form-data with boundary.
35	      headers.delete('Content-Type');
36	    } else if (!headers.has('Content-Type') && options.body !== undefined && options.body !== null) {
37	      headers.set('Content-Type', 'application/json');
38	    }
39	
40	    const res = await fetch(url, {
41	      ...options,
42	      headers,
43	    });
44	
45	    if (res.status === 401 || res.status === 403) {
46	      onAuthFailure();
47	    }
48	
49	    return res;
50	  };
51	}
