1	import React from 'react';
2	
3	interface TrendBadgeProps {
4	    trendDelta: number | null;
5	    size?: 'sm' | 'md';
6	}
7	
8	export default function TrendBadge({ trendDelta, size = 'md' }: TrendBadgeProps) {
9	    const label = getLabel(trendDelta);
10	    const { bg, fg } = getColors(trendDelta);
11	    const fontSize = size === 'sm' ? '0.7rem' : '0.8rem';
12	    const padding = size === 'sm' ? '1px 6px' : '2px 10px';
13	
14	    return (
15	        <span style={{
16	            display: 'inline-block', fontSize, padding, borderRadius: '9999px',
17	            background: bg, color: fg, fontWeight: 600,
18	        }}>
19	            {label}
20	        </span>
21	    );
22	}
23	
24	function getLabel(delta: number | null): string {
25	    if (delta === null) return 'stable';
26	    if (delta < -0.15) return 'critical';
27	    if (delta < -0.05) return 'degrading';
28	    if (delta > 0.05) return 'improving';
29	    return 'stable';
30	}
31	
32	function getColors(delta: number | null): { bg: string; fg: string } {
33	    if (delta === null) return { bg: '#f1f5f9', fg: '#64748b' };
34	    if (delta < -0.15) return { bg: '#fef2f2', fg: '#dc2626' };
35	    if (delta < -0.05) return { bg: '#fff7ed', fg: '#ea580c' };
36	    if (delta > 0.05) return { bg: '#f0fdf4', fg: '#16a34a' };
37	    return { bg: '#f1f5f9', fg: '#64748b' };
38	}
