27	        let timeoutId: NodeJS.Timeout;
28	
29	        const checkProfile = async (userId: string, attempts: number = 0) => {
30	            if (!isMounted) return;
31	            
32	            try {
33	                const { data, error } = await supabase
34	                    .from('user_profiles')
35	                    .select('access_status, agent_type, use_case, estimated_volume')
36	                    .eq('id', userId)
