1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import { API_BASE } from '../lib/config';
3	import { supabase } from '../supabaseClient';
4	
5	export interface ActionSettingsItem {
6	  actionId: string;
7	  actionName: string;
8	  requiredParams: string[];
9	  isActive: boolean;
10	  createdAt: string;
11	}
12	
13	interface ActionsApiRow {
14	  action_id: string;
15	  action_name: string;
16	  required_params: Record<string, unknown> | null;
17	  is_active: boolean;
18	  created_at: string;
19	}
20	
21	interface ActionsApiResponse {
22	  actions?: ActionsApiRow[];
23	  error?: string;
24	  details?: string;
25	}
26	
27	interface UseActionsSettingsResult {
28	  actions: ActionSettingsItem[];
29	  loading: boolean;
30	  error: string | null;
31	  refetch: () => void;
32	  registerAction: (name: string, requiredParams: string[]) => Promise<void>;
33	  toggleAction: (actionId: string, isActive: boolean) => Promise<void>;
34	}
35	
36	function extractParams(value: Record<string, unknown> | null): string[] {
37	  if (!value) {
38	    return [];
39	  }
40	  return Object.keys(value);
41	}
42	
43	async function getSessionToken(): Promise<string> {
44	  const {
45	    data: { session },
46	  } = await supabase.auth.getSession();
47	
48	  if (!session?.access_token) {
49	    throw new Error('Not authenticated');
50	  }
51	
52	  return session.access_token;
53	}
54	
55	function buildAuthHeaders(token: string): Record<string, string> {
56	  return {
57	    Authorization: `Bearer ${token}`,
58	    'Content-Type': 'application/json',
59	  };
60	}
61	
62	export function useActionsSettings(): UseActionsSettingsResult {
63	  const [actions, setActions] = useState<ActionSettingsItem[]>([]);
64	  const [loading, setLoading] = useState(true);
65	  const [error, setError] = useState<string | null>(null);
66	  const [tick, setTick] = useState(0);
67	
68	  const fetchActions = useCallback(async () => {
69	    if (!API_BASE) {
70	      setError('API endpoint is not configured. Set VITE_LAYERINFINITE_API_URL and redeploy.');
71	      setLoading(false);
72	      return;
73	    }
74	
75	    setLoading(true);
76	    setError(null);
77	
78	    try {
79	      const token = await getSessionToken();
80	      const response = await fetch(`${API_BASE}/v1/admin/actions?include_inactive=true`, {
81	        method: 'GET',
82	        headers: buildAuthHeaders(token),
83	      });
84	
85	      const payload = (await response.json()) as ActionsApiResponse;
86	      if (!response.ok) {
87	        throw new Error(payload.error ?? payload.details ?? 'Failed to fetch actions');
88	      }
89	
90	      const mapped = (payload.actions ?? []).map((row) => ({
91	        actionId: row.action_id,
92	        actionName: row.action_name,
93	        requiredParams: extractParams(row.required_params),
94	        isActive: row.is_active,
95	        createdAt: row.created_at,
96	      }));
97	
98	      setActions(mapped);
99	    } catch (err) {
100	      setError(err instanceof Error ? err.message : 'Failed to fetch actions');
101	      setActions([]);
102	    } finally {
103	      setLoading(false);
104	    }
105	  }, []);
106	
107	  useEffect(() => {
108	    void fetchActions();
109	  }, [fetchActions, tick]);
110	
111	  const registerAction = useCallback(async (name: string, requiredParams: string[]) => {
112	    if (!API_BASE) {
113	      throw new Error('API endpoint is not configured.');
114	    }
115	    const token = await getSessionToken();
116	
117	    const requiredParamsObject = requiredParams.reduce<Record<string, string>>((acc, item) => {
118	      acc[item] = 'required';
119	      return acc;
120	    }, {});
121	
122	    const response = await fetch(`${API_BASE}/v1/admin/register-action`, {
123	      method: 'POST',
124	      headers: buildAuthHeaders(token),
125	      body: JSON.stringify({
126	        action_name: name,
127	        required_params: requiredParamsObject,
128	      }),
129	    });
130	
131	    const payload = (await response.json()) as ActionsApiResponse;
132	    if (!response.ok) {
133	      throw new Error(payload.error ?? payload.details ?? 'Failed to register action');
134	    }
135	
136	    setTick((value) => value + 1);
137	  }, []);
138	
139	  const toggleAction = useCallback(async (actionId: string, isActive: boolean) => {
140	    if (!API_BASE) {
141	      throw new Error('API endpoint is not configured.');
142	    }
143	    const token = await getSessionToken();
144	
145	    const response = await fetch(`${API_BASE}/v1/admin/actions/${actionId}`, {
146	      method: 'PUT',
147	      headers: buildAuthHeaders(token),
148	      body: JSON.stringify({ is_active: !isActive }),
149	    });
150	
151	    const payload = (await response.json()) as ActionsApiResponse;
152	    if (!response.ok) {
153	      throw new Error(payload.error ?? payload.details ?? 'Failed to update action');
154	    }
155	
156	    setTick((value) => value + 1);
157	  }, []);
158	
159	  const refetch = useCallback(() => {
160	    setTick((value) => value + 1);
161	  }, []);
162	
163	  return useMemo(() => ({
164	    actions,
165	    loading,
166	    error,
167	    refetch,
168	    registerAction,
169	    toggleAction,
170	  }), [actions, loading, error, refetch, registerAction, toggleAction]);
171	}
