1	import { useCallback, useEffect, useMemo, useState } from 'react';
2	import { supabase } from '../supabaseClient';
3	import { ACCOUNT_SETUP_INCOMPLETE_MESSAGE, useCustomerContext } from './useCustomerContext';
4	
5	export type AlertsFilter =
6	  | 'all'
7	  | 'latency_spike'
8	  | 'context_drift'
9	  | 'coordinated_failure'
10	  | 'silent_failure';
11	
12	export interface AlertItem {
13	  id: string;
14	  alertType: string;
15	  severity: 'critical' | 'warning';
16	  message: string;
17	  actionName: string;
18	  currentValue: number | null;
19	  baselineValue: number | null;
20	  spikeRatio: number | null;
21	  affectedAgentCount: number | null;
22	  createdAt: string;
23	  resolved: boolean;
24	}
25	
26	export interface AlertsResult {
27	  alerts: AlertItem[];
28	  unresolvedCount: number;
29	  resolveAlert: (id: string) => Promise<void>;
30	  refetch: () => void;
31	  loading: boolean;
32	  error: string | null;
33	}
34	
35	interface AlertRow {
36	  alert_id: string;
37	  alert_type: string;
38	  severity: string | null;
39	  message: string | null;
40	  action_name: string | null;
41	  current_value: number | null;
42	  baseline_value: number | null;
43	  spike_ratio: number | null;
44	  affected_agent_count: number | null;
45	  detected_at: string | null;
46	  acknowledged: boolean | null;
47	}
48	
49	export function useAlerts(filter: AlertsFilter, showResolved: boolean): AlertsResult {
50	  const { data: ctx, loading: ctxLoading, error: ctxError } = useCustomerContext();
51	  const [alerts, setAlerts] = useState<AlertItem[]>([]);
52	  const [unresolvedCount, setUnresolvedCount] = useState(0);
53	  const [loading, setLoading] = useState(true);
54	  const [error, setError] = useState<string | null>(null);
55	  const [tick, setTick] = useState(0);
56	
57	  const ensureCustomerId = useCallback(async (): Promise<string> => {
58	    const {
59	      data: { user },
60	      error: userError,
61	    } = await supabase.auth.getUser();
62	
63	    if (userError || !user) {
64	      throw new Error(userError?.message ?? 'Unable to resolve authenticated user');
65	    }
66	
67	    const { data: profile, error: profileError } = await supabase
68	      .from('user_profiles')
69	      .select('customer_id')
70	      .eq('id', user.id)
71	      .single();
72	
73	    if (profileError || !profile?.customer_id) {
74	      throw new Error(ACCOUNT_SETUP_INCOMPLETE_MESSAGE);
75	    }
76	
77	    return profile.customer_id as string;
78	  }, []);
79	
80	  const load = useCallback(async () => {
81	    setLoading(true);
82	    setError(null);
83	
84	    try {
85	      const customerId = await ensureCustomerId();
86	
87	      if (!ctx) {
88	        setLoading(false);
89	        return;
90	      }
91	
92	      let query = supabase
93	        .from('degradation_alert_events')
94	        .select('alert_id, alert_type, severity, message, action_name, current_value, baseline_value, spike_ratio, affected_agent_count, detected_at, acknowledged')
95	        .eq('customer_id', customerId)
96	        .order('detected_at', { ascending: false })
97	        .limit(50);
98	
99	      if (!showResolved) {
100	        query = query.eq('acknowledged', false);
101	      }
102	
103	      if (filter !== 'all') {
104	        query = query.eq('alert_type', filter);
105	      }
106	
107	      const { data: rows, error: rowsError } = await query;
108	      if (rowsError) {
109	        throw new Error(rowsError.message);
110	      }
111	
112	      const mapped: AlertItem[] = ((rows ?? []) as AlertRow[]).map((row) => {
113	        const normalizedSeverity = (row.severity ?? '').toLowerCase();
114	        const severity: 'critical' | 'warning' = normalizedSeverity === 'critical'
115	          ? 'critical'
116	          : 'warning';
117	
118	        return {
119	          id: row.alert_id,
120	          alertType: row.alert_type,
121	          severity,
122	          message: row.message ?? '',
123	          actionName: row.action_name ?? '',
124	          currentValue: row.current_value,
125	          baselineValue: row.baseline_value,
126	          spikeRatio: row.spike_ratio,
127	          affectedAgentCount: row.affected_agent_count,
128	          createdAt: row.detected_at ?? new Date().toISOString(),
129	          resolved: Boolean(row.acknowledged),
130	        };
131	      });
132	
133	      const { count: unresolved, error: unresolvedError } = await supabase
134	        .from('degradation_alert_events')
135	        .select('alert_id', { count: 'exact', head: true })
136	        .eq('customer_id', customerId)
137	        .eq('acknowledged', false);
138	
139	      if (unresolvedError) {
140	        throw new Error(unresolvedError.message);
141	      }
142	
143	      setAlerts(mapped);
144	      setUnresolvedCount(unresolved ?? 0);
145	    } catch (err) {
146	      setError(err instanceof Error ? err.message : 'Failed to load alerts');
147	      setAlerts([]);
148	      setUnresolvedCount(0);
149	    } finally {
150	      setLoading(false);
151	    }
152	  }, [ctx, filter, showResolved, ensureCustomerId]);
153	
154	  useEffect(() => {
155	    if (!ctx) {
156	      if (!ctxLoading) {
157	        setLoading(false);
158	      }
159	      return;
160	    }
161	    void load();
162	  }, [ctx, ctxLoading, tick, load]);
163	
164	  useEffect(() => {
165	    if (!ctx) {
166	      return;
167	    }
168	
169	    const channel = supabase
170	      .channel(`alerts-${ctx.customerId}`)
171	      .on('postgres_changes', {
172	        event: 'INSERT',
173	        schema: 'public',
174	        table: 'degradation_alert_events',
175	        filter: `customer_id=eq.${ctx.customerId}`,
176	      }, () => {
177	        setTick((v) => v + 1);
178	      })
179	      .subscribe();
180	
181	    return () => {
182	      void channel.unsubscribe();
183	    };
184	  }, [ctx]);
185	
186	  const resolveAlert = useCallback(async (id: string) => {
187	    const customerId = await ensureCustomerId();
188	
189	    const { error: updateError } = await supabase
190	      .from('degradation_alert_events')
191	      .update({
192	        acknowledged: true,
193	        acknowledged_at: new Date().toISOString(),
194	      })
195	      .eq('customer_id', customerId)
196	      .eq('alert_id', id);
197	
198	    if (updateError) {
199	      throw new Error(updateError.message);
200	    }
201	
202	    setAlerts((prev) => prev.filter((row) => row.id !== id));
203	    setUnresolvedCount((prev) => Math.max(0, prev - 1));
204	  }, [ensureCustomerId]);
205	
206	  const refetch = useCallback(() => {
207	    setTick((v) => v + 1);
208	  }, []);
209	
210	  return useMemo(() => ({
211	    alerts,
212	    unresolvedCount,
213	    resolveAlert,
214	    refetch,
215	    loading: loading || ctxLoading,
216	    error: ctxError ?? error,
217	  }), [alerts, unresolvedCount, resolveAlert, refetch, loading, ctxLoading, ctxError, error]);
218	}
