1	import { useCallback, useEffect, useState } from 'react';
2	import { supabase } from '../supabaseClient';
3	import { API_BASE } from '../lib/config';
4	
5	export const ACCOUNT_SETUP_INCOMPLETE_MESSAGE = 'Account setup incomplete. Please sign out and sign in again to complete setup.';
6	
7	export interface CustomerContextData {
8	  userId: string;
9	  email: string;
10	  customerId: string;
11	  agentId: string;
12	  agentName: string;
13	}
14	
15	interface CustomerContextState {
16	  data: CustomerContextData | null;
17	  loading: boolean;
18	  error: string | null;
19	  refetch: () => Promise<void>;
20	}
21	
22	let contextCache: CustomerContextData | null = null;
23	let contextPromise: Promise<CustomerContextData> | null = null;
24	let contextGeneration = 0;
25	
26	async function tryBootstrapProfile(): Promise<void> {
27	  if (!API_BASE) {
28	    throw new Error(
29	      'API not configured. Set VITE_LAYERINFINITE_API_URL in your ' +
30	      'deployment environment and redeploy the dashboard.'
31	    );
32	  }
33	
34	  const {
35	    data: { session },
36	  } = await supabase.auth.getSession();
37	
38	  if (!session?.access_token) {
39	    return;
40	  }
41	
42	  try {
43	    await fetch(`${API_BASE}/v1/auth/api-keys`, {
44	      method: 'GET',
45	      headers: {
46	        Authorization: `Bearer ${session.access_token}`,
47	      },
48	    });
49	  } catch {
50	    // Best effort bootstrap call; context lookup below determines final state.
51	  }
52	}
53	
54	async function fetchCustomerContext(): Promise<CustomerContextData> {
55	  const {
56	    data: { user },
57	    error: userError,
58	  } = await supabase.auth.getUser();
59	
60	  if (userError || !user) {
61	    throw new Error(userError?.message ?? 'Unable to resolve authenticated user');
62	  }
63	
64	  let { data: profile, error: profileError } = await supabase
65	    .from('user_profiles')
66	    .select('customer_id')
67	    .eq('id', user.id)
68	    .single();
69	
70	  if (!profile?.customer_id) {
71	    await tryBootstrapProfile();
72	
73	    const retry = await supabase
74	      .from('user_profiles')
75	      .select('customer_id')
76	      .eq('id', user.id)
77	      .single();
78	
79	    profile = retry.data;
80	    profileError = retry.error;
81	  }
82	
83	  if (profileError || !profile?.customer_id) {
84	    throw new Error(ACCOUNT_SETUP_INCOMPLETE_MESSAGE);
85	  }
86	
87	  const { data: agent, error: agentError } = await supabase
88	    .from('dim_agents')
89	    .select('agent_id, agent_name')
90	    .eq('customer_id', profile.customer_id)
91	    .eq('is_active', true)
92	    .order('created_at', { ascending: true })
93	    .limit(1)
94	    .maybeSingle();
95	
96	  let resolvedAgent = agent;
97	
98	  if (!resolvedAgent?.agent_id) {
99	    const { data: fallbackAgent, error: fallbackError } = await supabase
100	      .from('dim_agents')
101	      .select('agent_id, agent_name')
102	      .eq('customer_id', profile.customer_id)
103	      .order('created_at', { ascending: true })
104	      .limit(1)
105	      .maybeSingle();
106	
107	    if (!fallbackError && fallbackAgent?.agent_id) {
108	      resolvedAgent = fallbackAgent;
109	    }
110	  }
111	
112	  return {
113	    userId: user.id,
114	    email: user.email ?? '',
115	    customerId: profile.customer_id,
116	    agentId: resolvedAgent?.agent_id ?? '',
117	    agentName: resolvedAgent?.agent_name ?? '',
118	  };
119	}
120	
121	async function resolveCustomerContext(forceRefresh = false): Promise<CustomerContextData> {
122	  if (forceRefresh) {
123	    contextCache = null;
124	    contextPromise = null;
125	  }
126	
127	  if (contextCache) {
128	    return contextCache;
129	  }
130	
131	  if (!contextPromise) {
132	    const capturedGen = contextGeneration;
133	    contextPromise = fetchCustomerContext().then((data) => {
134	      if (contextGeneration === capturedGen) {
135	        contextCache = data;
136	      }
137	      return data;
138	    }).finally(() => {
139	      contextPromise = null;
140	    });
141	  }
142	
143	  return contextPromise;
144	}
145	
146	export function useCustomerContext(): CustomerContextState {
147	  const [data, setData] = useState<CustomerContextData | null>(contextCache);
148	  const [loading, setLoading] = useState<boolean>(!contextCache);
149	  const [error, setError] = useState<string | null>(null);
150	
151	  const load = useCallback(async (forceRefresh = false) => {
152	    setLoading(true);
153	    setError(null);
154	    try {
155	      const resolved = await resolveCustomerContext(forceRefresh);
156	      setData(resolved);
157	    } catch (err) {
158	      const message = err instanceof Error ? err.message : 'Failed to load customer context';
159	      setError(message);
160	      setData(null);
161	    } finally {
162	      setLoading(false);
163	    }
164	  }, []);
165	
166	  useEffect(() => {
167	    if (contextCache) {
168	      setLoading(false);
169	      setData(contextCache);
170	      return;
171	    }
172	    void load();
173	  }, [load]);
174	
175	  useEffect(() => {
176	    const {
177	      data: { subscription },
178	    } = supabase.auth.onAuthStateChange((event) => {
179	      if (event === 'SIGNED_IN' || event === 'SIGNED_OUT' || event === 'USER_UPDATED') {
180	        contextGeneration++;
181	        contextCache = null;
182	        contextPromise = null;
183	      }
184	    });
185	
186	    return () => {
187	      subscription.unsubscribe();
188	    };
189	  }, []);
190	
191	  const refetch = useCallback(async () => {
192	    await load(true);
193	  }, [load]);
194	
195	  return { data, loading, error, refetch };
196	}
