1	import { useState, useCallback, useRef } from 'react';
2	
3	export type ToastType = 'critical' | 'warning' | 'info' | 'success';
4	
5	export interface Toast {
6	    id: string;
7	    message: string;
8	    type: ToastType;
9	    duration: number;
10	}
11	
12	let _idCounter = 0;
13	
14	export function useToast() {
15	    const [toasts, setToasts] = useState<Toast[]>([]);
16	    const timersRef = useRef<Map<string, ReturnType<typeof setTimeout>>>(new Map());
17	
18	    const dismissToast = useCallback((id: string) => {
19	        const timer = timersRef.current.get(id);
20	        if (timer) {
21	            clearTimeout(timer);
22	            timersRef.current.delete(id);
23	        }
24	        setToasts((prev) => prev.filter((t) => t.id !== id));
25	    }, []);
26	
27	    const showToast = useCallback(
28	        (message: string, type: ToastType = 'info', duration = 5000) => {
29	            const id = `toast-${++_idCounter}-${Date.now()}`;
30	            const toast: Toast = { id, message, type, duration };
31	
32	            setToasts((prev) => [...prev, toast]);
33	
34	            if (duration > 0) {
35	                const timer = setTimeout(() => {
36	                    timersRef.current.delete(id);
37	                    setToasts((prev) => prev.filter((t) => t.id !== id));
38	                }, duration);
39	                timersRef.current.set(id, timer);
40	            }
41	
42	            return id;
43	        },
44	        [],
45	    );
46	
47	    return { toasts, showToast, dismissToast };
48	}
