2	import { supabase } from '../supabaseClient';
3	import { ACCOUNT_SETUP_INCOMPLETE_MESSAGE, useCustomerContext } from './useCustomerContext';
4	
5	export type ActionTrend = 'improving' | 'degrading' | 'stable';
6	
7	export interface TopActionItem {
8	  actionName: string;
9	  successRate: number;
10	  trend: ActionTrend;
11	  trendDelta: number;
