17	  actionId: string;
18	  actionName: string;
19	  successRate: number;
20	  trendDelta: number;
21	}
22	
23	export interface TopActionsResult {
24	  topActions: TopActionItem[];
25	  degradingActions: DegradingActionItem[];
26	  loading: boolean;
27	  error: string | null;
28	  refetch: () => void;
29	}
30	
31	interface ActionScoreRow {
32	  action_id: string;
33	  action_name: string;
34	  weighted_success_rate: number | null;
35	  trend_delta: number | null;
36	  total_attempts: number | null;
37	}
38	
39	function getTrend(delta: number): ActionTrend {
40	  if (delta > 0.05) {
41	    return 'improving';
42	  }
43	  if (delta < -0.05) {
44	    return 'degrading';
45	  }
46	  return 'stable';
47	}
48	
49	function getBarColor(rate: number): string {
50	  if (rate >= 0.95) {
51	    return '#b8ff00';
52	  }
53	  if (rate >= 0.8) {
54	    return '#44dd66';
55	  }
56	  return '#ffaa00';
57	}
58	
59	export function useTopActions(): TopActionsResult {
60	  const { data: ctx, loading: ctxLoading, error: ctxError } = useCustomerContext();
61	  const [topActions, setTopActions] = useState<TopActionItem[]>([]);
62	  const [degradingActions, setDegradingActions] = useState<DegradingActionItem[]>([]);
63	  const [loading, setLoading] = useState(true);
64	  const [error, setError] = useState<string | null>(null);
65	  const [tick, setTick] = useState(0);
66	
67	  const ensureCustomerId = useCallback(async (): Promise<string> => {
68	    const {
69	      data: { user },
70	      error: userError,
71	    } = await supabase.auth.getUser();
72	
73	    if (userError || !user) {
74	      throw new Error(userError?.message ?? 'Unable to resolve authenticated user');
75	    }
76	
77	    const { data: profile, error: profileError } = await supabase
78	      .from('user_profiles')
79	      .select('customer_id')
80	      .eq('id', user.id)
81	      .single();
82	
83	    if (profileError || !profile?.customer_id) {
84	      throw new Error(ACCOUNT_SETUP_INCOMPLETE_MESSAGE);
85	    }
86	
87	    return profile.customer_id as string;
88	  }, []);
89	
90	  const load = useCallback(async () => {
91	    setLoading(true);
92	    setError(null);
93	
94	    try {
95	      const customerId = await ensureCustomerId();
96	
97	      if (!ctx) {
98	        setLoading(false);
99	        return;
100	      }
101	
102	      const { data: rows, error: rowsError } = await supabase
103	        .from('mv_action_scores')
104	        .select('action_id, action_name, weighted_success_rate, trend_delta, total_attempts')
105	        .eq('customer_id', customerId)
106	        .order('weighted_success_rate', { ascending: false });
107	
108	      if (rowsError) {
109	        throw new Error(rowsError.message);
110	      }
111	
112	      const typedRows = (rows ?? []) as ActionScoreRow[];
113	
114	      const top = typedRows.slice(0, 5).map((row) => {
115	        const rate = Number(row.weighted_success_rate ?? 0);
116	        const trendDelta = Number(row.trend_delta ?? 0);
117	        return {
118	          actionName: row.action_name,
119	          successRate: rate,
120	          trend: getTrend(trendDelta),
121	          trendDelta,
122	          sampleCount: Number(row.total_attempts ?? 0),
123	          barColor: getBarColor(rate),
124	        };
125	      });
126	
127	      const degrading = typedRows
128	        .filter((row) => Number(row.trend_delta ?? 0) < -0.05)
129	        .map((row) => ({
130	          actionId: row.action_id,
131	          actionName: row.action_name,
132	          successRate: Number(row.weighted_success_rate ?? 0),
133	          trendDelta: Number(row.trend_delta ?? 0),
134	        }));
135	
136	      setTopActions(top);
137	      setDegradingActions(degrading);
138	    } catch (err) {
139	      setError(err instanceof Error ? err.message : 'Failed to load action metrics');
140	      setTopActions([]);
141	      setDegradingActions([]);
142	    } finally {
143	      setLoading(false);
144	    }
145	  }, [ctx, ensureCustomerId]);
146	
147	  useEffect(() => {
148	    if (!ctx) {
149	      if (!ctxLoading) {
150	        setLoading(false);
151	      }
152	      return;
153	    }
154	    void load();
155	  }, [ctx, ctxLoading, tick, load]);
156	
157	  const refetch = useCallback(() => {
158	    setTick((v) => v + 1);
159	  }, []);
160	
161	  return useMemo(() => ({
162	    topActions,
163	    degradingActions,
164	    loading: loading || ctxLoading,
165	    error: ctxError ?? error,
166	    refetch,
167	  }), [topActions, degradingActions, loading, ctxLoading, ctxError, error, refetch]);
168	}
