1	/**
2	 * Layerinfinite — hooks/useAgentApiKey.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Provides the agent API key for calls to /v1/* agent routes.
5	 *
6	 * API CALL RULE: All calls to /v1/* MUST use the agent API key from localStorage.
7	 * NEVER use supabase.auth.getSession() token for agent routes.
8	 * The Supabase JWT is only valid for dashboard auth (user_profiles, etc.).
9	 * Agent API routes use SHA-256-hashed layerinfinite_XXXX keys in dim_agents.
10	 *
11	 * Key storage: localStorage key 'layerinfinite_api_key'
12	 * Key format:  layerinfinite_ + exactly 32 lowercase hex chars [0-9a-f]
13	 * (Matches the format generated by api-keys.ts: generateApiKey())
14	 *
15	 * On 401/403 response from any agent API call:
16	 *   - Clear the stale key from localStorage
17	 *   - Redirect to /onboarding?step=2&reason=expired
18	 *   - Show toast: "API key expired or missing. Please regenerate."
19	 * ══════════════════════════════════════════════════════════════
20	 */
21	
22	import { useCallback, useEffect, useMemo, useState } from 'react';
23	
24	// Matches the output of generateApiKey() in api/routes/auth/api-keys.ts:
25	//   `layerinfinite_${hex}` where hex is 16 random bytes → 32 lowercase hex chars.
26	// Condition verified: api-keys.ts uses new Uint8Array(16) + b.toString(16).padStart(2,'0')
27	// → 32 chars of [0-9a-f]. This regex must match that exact output.
28	const API_KEY_REGEX = /^layerinfinite_[0-9a-f]{32}$/;
29	
30	export const AGENT_API_KEY_STORAGE_KEY = 'layerinfinite_api_key';
31	
32	export interface AgentApiKeyResult {
33	  /** The validated API key, or null if missing/invalid */
34	  apiKey: string | null;
35	  /** True if the key is present and passes format validation */
36	  isValid: boolean;
37	  /** Error message when key is missing or invalid format */
38	  error: string | null;
39	  /** Call this after storing a new key to refresh the hook state */
40	  refresh: () => void;
41	  /**
42	   * Call this when a /v1/* request returns 401 or 403.
43	   * Clears the key and redirects to onboarding step 2.
44	   */
45	  handleAuthFailure: () => void;
46	}
47	
48	function readAndValidateKey(): { key: string | null; error: string | null } {
49	  try {
50	    const stored = localStorage.getItem(AGENT_API_KEY_STORAGE_KEY) ?? '';
51	    if (!stored) {
52	      return { key: null, error: 'No API key found. Create one in Settings → API Keys.' };
53	    }
54	    if (!API_KEY_REGEX.test(stored)) {
55	      // Key is present but malformed — clear it to avoid a silent loop
56	      localStorage.removeItem(AGENT_API_KEY_STORAGE_KEY);
57	      return { key: null, error: 'Stored API key has an invalid format. Please regenerate.' };
58	    }
59	    return { key: stored, error: null };
60	  } catch {
61	    // localStorage unavailable (private mode, etc.)
62	    return { key: null, error: 'Unable to read API key from storage.' };
63	  }
64	}
65	
66	export function useAgentApiKey(): AgentApiKeyResult {
67	  const [tick, setTick] = useState(0);
68	
69	  // ← KEY FIX: useMemo(fn, [tick]) ensures readAndValidateKey()
70	  // re-runs every time refresh() is called or tick changes.
71	  // Without this, React reuses the stale result from the first render.
72	  const { key, error } = useMemo(() => readAndValidateKey(), [tick]);
73	
74	  useEffect(() => {
75	    const handler = (e: StorageEvent) => {
76	      if (e.key === AGENT_API_KEY_STORAGE_KEY) {
77	        setTick((v) => v + 1);
78	      }
79	    };
80	    window.addEventListener('storage', handler);
81	    return () => window.removeEventListener('storage', handler);
82	  }, []);
83	
84	  const refresh = useCallback(() => {
85	    setTick((v) => v + 1);
86	  }, []);
87	
88	  const handleAuthFailure = useCallback(() => {
89	    try {
90	      localStorage.removeItem(AGENT_API_KEY_STORAGE_KEY);
91	    } catch {
92	      // ignore
93	    }
94	    // Redirect to onboarding step 2 so the user can regenerate their key
95	    window.location.href = '/onboarding?step=2&reason=expired';
96	  }, []);
97	
98	  return {
99	    apiKey: key,
100	    isValid: key !== null,
101	    error,
102	    refresh,
103	    handleAuthFailure,
104	  };
105	}
