1	// REQUIRES: Realtime enabled on agent_trust_scores in Supabase Dashboard
2	// → Table Editor → agent_trust_scores → Realtime toggle → ON
3	
4	import { useEffect, useRef, useState } from 'react';
5	import { supabase } from '../supabaseClient';
6	
7	type TrustStatus = 'trusted' | 'probation' | 'sandbox' | 'suspended' | 'new';
8	
9	function normalizeTrustStatus(value: string | null | undefined): TrustStatus {
10	    const normalized = (value ?? '').toLowerCase();
11	    if (normalized === 'degraded') return 'sandbox';
12	    if (normalized === 'trusted' || normalized === 'probation' || normalized === 'sandbox' || normalized === 'suspended' || normalized === 'new') {
13	        return normalized;
14	    }
15	    return 'probation';
16	}
17	
18	export interface TrustRow {
19	    trust_id: string;
20	    agent_id: string;
21	    trust_score: number;
22	    trust_status: TrustStatus;
23	    consecutive_failures: number;
24	    total_decisions: number;
25	    correct_decisions: number;
26	}
27	
28	export function useRealtimeTrust(
29	    onTrustChange: (trust: TrustRow) => void,
30	): { isConnected: boolean } {
31	    const [isConnected, setIsConnected] = useState(false);
32	    const channelId = useRef(crypto.randomUUID());
33	    const onTrustChangeRef = useRef(onTrustChange);
34	    onTrustChangeRef.current = onTrustChange;
35	
36	    useEffect(() => {
37	        const channel = supabase
38	            .channel(`realtime-trust-${channelId.current}`)
39	            .on<TrustRow>(
40	                'postgres_changes',
41	                { event: 'INSERT', schema: 'public', table: 'agent_trust_scores' },
42	                (payload) => {
43	                    onTrustChangeRef.current({
44	                        ...payload.new,
45	                        trust_status: normalizeTrustStatus((payload.new as any).trust_status),
46	                    });
47	                },
48	            )
49	            .on<TrustRow>(
50	                'postgres_changes',
51	                { event: 'UPDATE', schema: 'public', table: 'agent_trust_scores' },
52	                (payload) => {
53	                    onTrustChangeRef.current({
54	                        ...payload.new,
55	                        trust_status: normalizeTrustStatus((payload.new as any).trust_status),
56	                    });
57	                },
58	            )
59	            .subscribe((status) => {
60	                setIsConnected(status === 'SUBSCRIBED');
61	            });
62	
63	        return () => { void supabase.removeChannel(channel); };
64	    }, []); // subscribe once
65	
66	    return { isConnected };
67	}
