30	function getIsoBounds(hoursAgoStart: number, hoursAgoEnd: number): { from: string; to: string } {
31	  const end = new Date(Date.now() - hoursAgoEnd * 60 * 60 * 1000);
32	  const start = new Date(Date.now() - hoursAgoStart * 60 * 60 * 1000);
33	  return { from: start.toISOString(), to: end.toISOString() };
34	}
35	
36	function isUuid(value: string): boolean {
37	  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(value);
38	}
39	
40	export function useOverviewMetrics(): OverviewMetrics {
41	  const { data: ctx, loading: ctxLoading, error: ctxError } = useCustomerContext();
42	  const [hasScores, setHasScores] = useState(false);
43	  const [hasData, setHasData] = useState(false);
44	  const [agentHealthScore, setAgentHealthScore] = useState(0);
45	  const [agentHealthDelta, setAgentHealthDelta] = useState(0);
46	  const [decisionsToday, setDecisionsToday] = useState(0);
47	  const [decisionsDelta, setDecisionsDelta] = useState(0);
48	  const [successRate7d, setSuccessRate7d] = useState(0);
49	  const [successRateDelta, setSuccessRateDelta] = useState(0);
50	  const [activeAlerts, setActiveAlerts] = useState(0);
51	  const [alertSeverity, setAlertSeverity] = useState<'critical' | 'warning' | 'none'>('none');
52	  const [loading, setLoading] = useState(true);
53	  const [error, setError] = useState<string | null>(null);
54	  const [refreshTick, setRefreshTick] = useState(0);
55	
56	  const ensureCustomerId = useCallback(async (): Promise<string> => {
57	    const {
58	      data: { user },
59	      error: userError,
60	    } = await supabase.auth.getUser();
61	
62	    if (userError || !user) {
63	      throw new Error(userError?.message ?? 'Unable to resolve authenticated user');
64	    }
65	
66	    const { data: profile, error: profileError } = await supabase
67	      .from('user_profiles')
