71	
72	    if (profileError || !profile?.customer_id) {
73	      throw new Error(ACCOUNT_SETUP_INCOMPLETE_MESSAGE);
74	    }
75	
76	    return profile.customer_id as string;
77	  }, []);
78	
79	  const loadMetrics = useCallback(async () => {
80	    setLoading(true);
81	    setError(null);
82	    setHasScores(false);
83	    setHasData(false);
84	
85	    try {
86	      const customerId = await ensureCustomerId();
87	
88	      if (!ctx) {
89	        setLoading(false);
90	        return;
91	      }
92	
93	      let trustRow: Record<string, unknown> | undefined;
94	      if (isUuid(ctx.agentId)) {
95	        const { data: trustRows, error: trustError } = await supabase
96	          .from('agent_trust_scores')
97	          .select('*')
98	          .eq('agent_id', ctx.agentId)
99	          .limit(1);
100	
101	        if (trustError) {
102	          throw new Error(trustError.message);
103	        }
104	
105	        trustRow = trustRows?.[0] as Record<string, unknown> | undefined;
106	      }
107	
108	      const trustScore = Number((trustRow?.trust_score as number | null) ?? 0);
109	      const totalDecisions = Number((trustRow?.total_decisions as number | null) ?? 0);
110	      setHasData(totalDecisions > 0);
111	
112	      const todayBounds = getIsoBounds(24, 0);
113	      const previousBounds = getIsoBounds(48, 24);
114	
115	      const { count: todayCount, error: todayError } = await supabase
116	        .from('fact_outcomes')
117	        .select('outcome_id', { count: 'exact', head: true })
118	        .eq('customer_id', customerId)
119	        .gte('timestamp', todayBounds.from)
120	        .lt('timestamp', todayBounds.to);
121	
122	      if (todayError) {
123	        throw new Error(todayError.message);
124	      }
125	
126	      const { count: previousCount, error: previousError } = await supabase
127	        .from('fact_outcomes')
128	        .select('outcome_id', { count: 'exact', head: true })
129	        .eq('customer_id', customerId)
130	        .gte('timestamp', previousBounds.from)
131	        .lt('timestamp', previousBounds.to);
132	
133	      if (previousError) {
134	        throw new Error(previousError.message);
135	      }
136	
137	      const { data: actionRows, error: actionError } = await supabase
138	        .from('mv_action_scores')
139	        .select('weighted_success_rate, trend_delta')
