142	      if (actionError) {
143	        throw new Error(actionError.message);
144	      }
145	
146	      const typedRows = (actionRows ?? []) as ActionScoreRow[];
147	      const actionCount = typedRows.length;
148	      setHasScores(actionCount > 0);
149	      const currentRate = actionCount > 0
150	        ? typedRows.reduce((sum, row) => sum + Number(row.weighted_success_rate ?? 0), 0) / actionCount
151	        : 0;
152	
153	      const baselineRate = actionCount > 0
154	        ? typedRows.reduce((sum, row) => {
155	          const weighted = Number(row.weighted_success_rate ?? 0);
156	          const trend = Number(row.trend_delta ?? 0);
157	          return sum + (weighted - trend);
158	        }, 0) / actionCount
159	        : 0;
160	
161	      const { count: unresolvedCount, error: unresolvedError } = await supabase
162	        .from('degradation_alert_events')
163	        .select('alert_id', { count: 'exact', head: true })
164	        .eq('customer_id', customerId)
165	        .eq('acknowledged', false);
