186	        ? 'critical'
187	        : normalizedSeverities.includes('warning')
188	          ? 'warning'
189	          : 'none';
190	
191	      const nextHealthScore = Math.round((trustScore * 0.5 + currentRate * 0.5) * 100);
192	      const previousHealthScore = Math.round((trustScore * 0.5 + baselineRate * 0.5) * 100);
193	
194	      setAgentHealthScore(nextHealthScore);
195	      setAgentHealthDelta(nextHealthScore - previousHealthScore);
196	      setDecisionsToday(todayCount ?? 0);
197	      setDecisionsDelta((todayCount ?? 0) - (previousCount ?? 0));
198	      setSuccessRate7d(currentRate);
199	      setSuccessRateDelta((currentRate - baselineRate) * 100);
200	      setActiveAlerts(unresolvedCount ?? 0);
201	      setAlertSeverity(nextAlertSeverity);
202	    } catch (err) {
203	      setError(err instanceof Error ? err.message : 'Failed to fetch overview metrics');
204	    } finally {
205	      setLoading(false);
206	    }
207	  }, [ctx, ensureCustomerId]);
208	
209	  useEffect(() => {
210	    if (!ctx) {
211	      if (!ctxLoading) {
212	        setLoading(false);
213	      }
