244	    };
245	  }, [ctx]);
246	
247	  useEffect(() => {
248	    if (!ctx) {
249	      return;
250	    }
251	
252	    const timer = window.setInterval(() => {
253	      setRefreshTick((v) => v + 1);
254	    }, 30000);
255	
256	    return () => {
257	      window.clearInterval(timer);
258	    };
259	  }, [ctx]);
260	
261	  const refetch = useCallback(() => {
262	    setRefreshTick((v) => v + 1);
263	  }, []);
264	
265	  return useMemo(() => ({
266	    hasScores,
267	    hasData,
268	    agentHealthScore,
269	    agentHealthDelta,
270	    decisionsToday,
271	    decisionsDelta,
272	    successRate7d,
273	    successRateDelta,
274	    activeAlerts,
275	    alertSeverity,
276	    loading: loading || ctxLoading,
277	    error: ctxError ?? error,
278	    refetch,
279	  }), [
280	    hasScores,
281	    hasData,
282	    agentHealthScore,
283	    agentHealthDelta,
284	    decisionsToday,
285	    decisionsDelta,
286	    successRate7d,
287	    successRateDelta,
288	    activeAlerts,
