56	  }
57	
58	  return fetch(`${API_BASE}${path}`, {
59	    ...init,
60	    headers: {
61	      ...(init.headers ?? {}),
62	      Authorization: `Bearer ${jwt}`,
63	      'Content-Type': 'application/json',
64	    },
65	  });
66	}
