16	async function auditFetch(params: string): Promise<Response> {
17	  const agentKey = getSafeStoredKey();
18	  if (agentKey) {
19	    return fetch(`${API_BASE}/v1/audit?${params}`, {
20	      headers: { 'X-API-Key': agentKey, 'Content-Type': 'application/json' },
21	    });
22	  }
23	  const { data: { session } } = await supabase.auth.getSession();
24	  if (!session) throw new Error('Session expired — please sign in again.');
25	  return fetch(`${API_BASE}/v1/audit?${params}`, {
26	    headers: { Authorization: `Bearer ${session.access_token}`, 'Content-Type': 'application/json' },
27	  });
28	}
