1	/**
2	 * LAYERINFINITE — Settings → Import History
3	 * ══════════════════════════════════════════════════════════════
4	 * Upload historical agent log files to seed the scoring engine
5	 * before SDK integration. Same API key = seamless continuity.
6	 *
7	 * Flow:
8	 *   1. User selects a file (JSON / JSONL / CSV)
9	 *   2. Dry-run preview shows: task clusters, quality score, row errors
10	 *   3. User confirms → POST /v1/import queues the job
11	 *   4. Progress bar polls GET /v1/import/:job_id until done
12	 *   5. Completion summary with link to Recommendations
13	 * ══════════════════════════════════════════════════════════════
14	 */
15	
16	import React, { useCallback, useRef, useState } from 'react';
17	import { Link } from 'react-router-dom';
18	import { API_BASE } from '../../../lib/config';
19	import { AGENT_API_KEY_STORAGE_KEY, useAgentApiKey } from '../../../hooks/useAgentApiKey';
20	import { createAgentFetch } from '../../../lib/api';
21	import { useToastContext } from '../../../components/Toast';
22	
23	// ── Types ─────────────────────────────────────────────────────
24	
25	interface TaskCluster {
26	  task_name: string;
27	  count: number;
28	  share: number;
29	}
30	
31	interface QualitySummary {
32	  avg_quality: number;
33	  inconsistency_rate: number;
34	  score_origin_breakdown: { provided: number; inferred: number };
35	  quality_gate: 'pass' | 'warn' | 'blocked';
36	}
37	
38	interface RowError {
39	  row: number;
40	  field: string;
41	  reason: string;
42	}
43	
44	interface PreviewData {
45	  job_id?: string;
46	  dry_run?: boolean;
47	  queued_rows: number;
48	  validation_errors: RowError[];
49	  task_clusters: TaskCluster[];
50	  quality_summary: QualitySummary;
51	}
52	
53	interface JobStatus {
54	  job_id: string;
55	  status: 'queued' | 'running' | 'done' | 'failed' | 'blocked';
56	  queued_rows: number;
57	  rows_processed: number;
58	  rows_failed: number;
59	  errors: Array<{ row: number; error: string }>;
60	  progress_pct: number;
61	  completed_at: string | null;
62	}
63	
64	interface MeResponse {
65	  agent_id?: string;
66	  agent_name?: string;
67	  customer_id?: string;
68	  error?: string;
69	}
70	
71	type UploadStage =
72	  | 'idle'
73	  | 'parsing'     // client-side file read
74	  | 'previewing'  // dry-run result shown, awaiting user confirm
75	  | 'uploading'   // job queued, polling
76	  | 'done'
77	  | 'error';
78	
79	// ── Helpers ───────────────────────────────────────────────────
80	
81	function qualityColor(gate: QualitySummary['quality_gate']): string {
82	  if (gate === 'pass') return 'text-[#00cc66]';
83	  if (gate === 'warn') return 'text-[#ffaa00]';
84	  return 'text-[#ff4444]';
85	}
86	
87	function qualityBg(gate: QualitySummary['quality_gate']): string {
88	  if (gate === 'pass') return 'bg-[#00cc66]/10 border-[#00cc66]/30';
89	  if (gate === 'warn') return 'bg-[#ffaa00]/10 border-[#ffaa00]/30';
90	  return 'bg-[#ff4444]/10 border-[#ff4444]/30';
91	}
92	
93	function formatQuality(q: number): string {
94	  return `${Math.round(q * 100)}%`;
95	}
96	
97	const API_KEY_REGEX = /^layerinfinite_[0-9a-f]{32}$/;
98	
99	// ── Component ─────────────────────────────────────────────────
100	
101	export default function ImportSettings(): React.ReactElement {
102	  const { handleAuthFailure } = useAgentApiKey();
103	  const { showToast } = useToastContext();
104	  const fileInputRef = useRef<HTMLInputElement>(null);
105	
106	  const [stage, setStage] = useState<UploadStage>('idle');
107	  const [selectedFile, setSelectedFile] = useState<File | null>(null);
108	  const [preview, setPreview] = useState<PreviewData | null>(null);
109	  const [job, setJob] = useState<JobStatus | null>(null);
110	  const [errorMsg, setErrorMsg] = useState<string | null>(null);
111	  const [pollHandle, setPollHandle] = useState<ReturnType<typeof setInterval> | null>(null);
112	
113	  const [apiKeyInput, setApiKeyInput] = useState<string>('');
114	  const [agentNameInput, setAgentNameInput] = useState<string>('');
115	  const [credentialsVerified, setCredentialsVerified] = useState<boolean>(false);
116	  const [credentialError, setCredentialError] = useState<string | null>(null);
117	  const [verifyingCredentials, setVerifyingCredentials] = useState<boolean>(false);
118	  const [verifiedIdentity, setVerifiedIdentity] = useState<{
119	    agentId: string;
120	    customerId: string;
121	    agentName: string;
122	  } | null>(null);
123	
124	  const effectiveApiKey = apiKeyInput.trim();
125	
126	  const agentFetch = useCallback(
127	    (url: string, opts?: RequestInit) => {
128	      if (!effectiveApiKey) throw new Error('No API key');
129	      return createAgentFetch(effectiveApiKey, handleAuthFailure)(url, opts);
130	    },
131	    [effectiveApiKey, handleAuthFailure],
132	  );
133	
134	  const handleVerifyCredentials = useCallback(async () => {
135	    const assertedAgentName = agentNameInput.trim();
136	
137	    setCredentialError(null);
138	    setVerifiedIdentity(null);
139	    setCredentialsVerified(false);
140	
141	    if (!effectiveApiKey) {
142	      setCredentialError('API key is required before uploading.');
143	      return;
144	    }
145	
146	    if (!API_KEY_REGEX.test(effectiveApiKey)) {
147	      setCredentialError('API key format is invalid. Expected layerinfinite_ + 32 hex chars.');
148	      return;
149	    }
150	
151	    if (!assertedAgentName) {
152	      setCredentialError('Agent name is required before uploading.');
153	      return;
154	    }
155	
156	    setVerifyingCredentials(true);
157	
158	    try {
159	      const verifyFetch = createAgentFetch(effectiveApiKey, handleAuthFailure);
160	      const res = await verifyFetch(`${API_BASE}/v1/me`, { method: 'GET' });
161	      const me = (await res.json()) as MeResponse;
162	
163	      if (!res.ok) {
164	        setCredentialError(me.error ?? `Failed to verify credentials (${res.status}).`);
165	        return;
166	      }
167	
168	      if (!me.agent_name || !me.agent_id || !me.customer_id) {
169	        setCredentialError('Credential verification failed: missing identity fields from /v1/me.');
170	        return;
171	      }
