22	/** True if the action was deactivated within the last hour (likely circuit-broken by agent). */
23	function isRecentlyCircuitBroken(action: Action): boolean {
24	  if (action.is_active) return false;
25	  if (!action.updated_at) return false;
26	  const updatedAt = new Date(action.updated_at).getTime();
27	  if (isNaN(updatedAt)) return false;
28	  const oneHourAgo = Date.now() - 60 * 60 * 1000;
29	  return updatedAt > oneHourAgo;
30	}
