79	
80	    if (updateError) {
81	      showToast(updateError.message, 'critical', 5000);
82	      return;
83	    }
84	    setActions(prev => prev.map(a =>
85	      a.action_id === actionId
86	        ? { ...a, is_active: !currentState }
87	        : a
88	    ));
89	    showToast('Action updated.', 'success', 2500);
90	  };
91	
92	  const registerAction = async (payload: {
93	    action_name: string;
94	    action_category: string;
95	    action_description: string;
96	    validation_mode: string;
97	  }): Promise<void> => {
98	    const { error: insertError } = await supabase
99	      .from('dim_actions')
100	      .insert({
101	        ...payload,
102	        required_params: [],
103	        is_active: true,
104	      });
105	
106	    if (insertError) {
107	      throw new Error(insertError.message);
108	    }
109	    setShowForm(false);
110	    await fetchActions();
111	  };
112	
