114	    event.preventDefault();
115	
116	    if (!formData.action_name.trim()) {
117	      return;
118	    }
119	
120	    setSaving(true);
121	    try {
122	      await registerAction(formData);
123	      showToast('Action registered successfully.', 'success', 3500);
124	      setFormData({
125	        action_name: '',
126	        action_category: 'custom',
127	        action_description: '',
128	        validation_mode: 'none',
129	      });
130	    } catch (err) {
131	      showToast(err instanceof Error ? err.message : 'Failed to register action', 'critical', 5000);
132	    } finally {
133	      setSaving(false);
134	    }
135	  };
136	
137	  return (
138	    <div className="text-white">
139	      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 mb-4">
140	        <div>
141	          <h2 className="text-2xl font-bold">Actions Registry</h2>
142	          <p className="text-sm text-[#a1a1aa] mt-1">Customer-scoped actions from dim_actions with RLS enforcement.</p>
143	        </div>
144	        <button
145	          className="bg-[#b8ff00] hover:bg-[#a5e800] text-black font-semibold px-4 py-2 rounded-lg"
146	          onClick={() => setShowForm((value) => !value)}
147	        >
148	          Register New Action
149	        </button>
150	      </div>
151	
152	      <div className="bg-[#b8ff00]/5 border border-[#b8ff00]/20 rounded-xl px-5 py-3 mb-6 flex items-center gap-3">
153	        <span className="text-[#b8ff00]">⚡</span>
154	        <p className="text-[#a1a1aa] text-sm">
155	          Actions are{' '}
156	          <strong className="text-white">auto-discovered</strong>
157	          {' '}when your agent logs outcomes via the SDK or MCP server.
158	          You can also register actions manually or
159	          disable specific actions here. Actions marked{' '}
160	          <span className="text-[#ff4444] font-semibold">CIRCUIT BROKEN</span>{' '}
161	          were recently disabled by your agent due to repeated failures.
162	        </p>
163	      </div>
164	
165	      <section className={`bg-[#111118] border border-[#1a1a24] rounded-xl p-5 mb-6 transition-all duration-300 ${showForm ? 'block' : 'hidden'}`}>
166	        <form onSubmit={handleSubmit} className="space-y-4">
167	          <div>
168	            <label className="text-xs text-[#a1a1aa] block mb-1">Action Name</label>
169	            <input
170	              className="w-full bg-[#0a0a0f] border border-[#1a1a24] rounded-lg px-3 py-2 text-sm font-mono"
171	              placeholder="e.g. clear_cache"
172	              value={formData.action_name}
173	              onChange={(event) => setFormData(prev => ({ ...prev, action_name: event.target.value }))}
174	              required
175	            />
176	          </div>
177	
178	          <div>
179	            <label className="text-xs text-[#a1a1aa] block mb-1">Category</label>
180	            <input
181	              className="w-full bg-[#0a0a0f] border border-[#1a1a24] rounded-lg px-3 py-2 text-sm"
182	              placeholder="custom"
183	              value={formData.action_category}
184	              onChange={(event) => setFormData(prev => ({ ...prev, action_category: event.target.value }))}
185	            />
186	          </div>
187	
188	          <div>
189	            <label className="text-xs text-[#a1a1aa] block mb-1">Description</label>
190	            <input
191	              className="w-full bg-[#0a0a0f] border border-[#1a1a24] rounded-lg px-3 py-2 text-sm"
192	              placeholder="What this action does"
193	              value={formData.action_description}
194	              onChange={(event) => setFormData(prev => ({ ...prev, action_description: event.target.value }))}
195	            />
196	          </div>
197	
198	          <div>
199	            <label className="text-xs text-[#a1a1aa] block mb-1">Validation Mode</label>
200	            <input
201	              className="w-full bg-[#0a0a0f] border border-[#1a1a24] rounded-lg px-3 py-2 text-sm"
202	              placeholder="none"
203	              value={formData.validation_mode}
204	              onChange={(event) => setFormData(prev => ({ ...prev, validation_mode: event.target.value }))}
205	            />
206	          </div>
207	
208	          <div className="flex items-center gap-3">
209	            <button
210	              type="submit"
211	              disabled={saving}
212	              className="bg-[#00cc66] hover:bg-[#00b55a] text-black font-semibold px-4 py-2 rounded-lg disabled:opacity-60"
213	            >
214	              {saving ? 'Saving...' : 'Submit'}
215	            </button>
216	            <button
217	              type="button"
218	              onClick={() => setShowForm(false)}
219	              className="border border-[#1a1a24] text-[#a1a1aa] hover:text-white rounded-lg px-4 py-2"
