237	            <div className="h-10 rounded-lg bg-[#0a0a0f] border border-[#1a1a24] animate-pulse" />
238	            <div className="h-10 rounded-lg bg-[#0a0a0f] border border-[#1a1a24] animate-pulse" />
239	            <div className="h-10 rounded-lg bg-[#0a0a0f] border border-[#1a1a24] animate-pulse" />
240	          </div>
241	        ) : actions.length === 0 ? (
242	          <div className="flex flex-col items-center justify-center py-24 text-center">
243	            <div className="text-5xl mb-4 opacity-20">⚡</div>
