267	                  <th className="text-left px-4 py-3 font-medium">REGISTERED</th>
268	                  <th className="text-left px-4 py-3 font-medium">ACTIONS</th>
269	                </tr>
270	              </thead>
271	              <tbody>
272	                {actions.map((action) => (
273	                  <tr key={action.action_id} className="border-b border-[#1a1a24]/70">
274	                    <td className="px-4 py-3 text-white font-mono text-sm">{action.action_name}</td>
275	                    <td className="px-4 py-3 text-[#a1a1aa]">{action.action_category ?? 'custom'}</td>
276	                    <td className="px-4 py-3">
277	                      <span className={action.is_active
278	                        ? 'text-[10px] font-bold px-2 py-1 rounded-full bg-[#00cc66]/10 text-[#00cc66] border border-[#00cc66]/30'
279	                        : isRecentlyCircuitBroken(action)
280	                          ? 'text-[10px] font-bold px-2 py-1 rounded-full bg-[#ff4444]/10 text-[#ff4444] border border-[#ff4444]/30'
281	                          : 'text-[10px] font-bold px-2 py-1 rounded-full bg-[#52525b]/20 text-[#a1a1aa] border border-[#52525b]/30'}
282	                      >
283	                        {action.is_active ? 'ACTIVE' : isRecentlyCircuitBroken(action) ? 'CIRCUIT BROKEN' : 'INACTIVE'}
284	                      </span>
