287	                      {action.created_at ? (() => { try { const d = new Date(action.created_at!); return isNaN(d.getTime()) ? '—' : format(d, 'MMM dd, yyyy'); } catch { return '—'; } })() : '—'}
288	                    </td>
289	                    <td className="px-4 py-3">
